// src/core/store/actions.ts

export const ActionType = {
  PAN: 'PAN',
  ZOOM: 'ZOOM',
  SET_VIEWPORT: 'SET_VIEWPORT',
  SET_RIGHT_MARGIN: 'SET_RIGHT_MARGIN',
  RESIZE: 'RESIZE',
  SET_TOTAL_BARS: 'SET_TOTAL_BARS',
  START_DRAG: 'START_DRAG',
  DRAG: 'DRAG',
  END_DRAG: 'END_DRAG',
  START_PINCH: 'START_PINCH',
  PINCH: 'PINCH',
  END_PINCH: 'END_PINCH',
  HOVER: 'HOVER',
  LEAVE: 'LEAVE',
} as const;

export type Action =
  | { type: typeof ActionType.PAN; deltaBars: number }
  | { type: typeof ActionType.ZOOM; factor: number; centerX: number }
  | { type: typeof ActionType.SET_VIEWPORT; startIndex: number; visibleCount: number }
  | { type: typeof ActionType.SET_RIGHT_MARGIN; rightMargin: number }
  | { type: typeof ActionType.RESIZE; width: number; height: number; dpr: number }
  | { type: typeof ActionType.SET_TOTAL_BARS; count: number }
  | { type: typeof ActionType.START_DRAG; x: number }
  | { type: typeof ActionType.DRAG; x: number }
  | { type: typeof ActionType.END_DRAG }
  | { type: typeof ActionType.START_PINCH; scale: number; centerX: number }
  | { type: typeof ActionType.PINCH; scale: number; centerX: number }
  | { type: typeof ActionType.END_PINCH }
  | { type: typeof ActionType.HOVER; x: number; y: number }
  | { type: typeof ActionType.LEAVE };
