import type { Action } from './store/actions';
import { coalesce } from './actionQueue';
import type { PerformanceTracker } from './perf';

type ApplyActions = (actions: Action[]) => boolean;
type Render = () => void;
type FrameRequestId = number | ReturnType<typeof setTimeout>;

export class RenderScheduler {
  private pendingActions: Action[] = [];
  private microtaskScheduled = false;
  private rafId: FrameRequestId | null = null;
  private paused = false;

  private requestFrame(cb: () => void): FrameRequestId {
    if (typeof requestAnimationFrame === 'function') {
      return requestAnimationFrame(cb);
    }
    // Fallback for non-browser environments
    return setTimeout(cb, 16);
  }

  private cancelFrame(id: FrameRequestId): void {
    if (typeof cancelAnimationFrame === 'function' && typeof id === 'number') {
      cancelAnimationFrame(id);
      return;
    }
    clearTimeout(id);
  }

  constructor(
    private readonly applyActions: ApplyActions,
    private readonly render: Render,
    private readonly perfTracker?: PerformanceTracker,
  ) {}

  enqueue(action: Action): void {
    this.pendingActions.push(action);
    this.scheduleMicrotask();
  }

  enqueueBatch(actions: Action[]): void {
    if (actions.length === 0) return;
    // R8: Zero-Copy Safe Push (avoid spread stack overflow on large batches)
    const len = actions.length;
    for (let i = 0; i < len; i++) {
      this.pendingActions.push(actions[i]);
    }
    this.scheduleMicrotask();
  }

  flushSync(): void {
    // Cancel pending rAF to avoid double render in the same frame
    if (this.rafId !== null) {
      this.cancelFrame(this.rafId);
      this.rafId = null;
    }
    const changed = this.flushActions();
    if (changed) {
      this.render();
    }
  }

  pause(): void {
    this.paused = true;
    if (this.rafId !== null) {
      this.cancelFrame(this.rafId);
      this.rafId = null;
    }
  }

  resume(): void {
    this.paused = false;
    this.scheduleRender();
  }

  destroy(): void {
    this.pendingActions = [];
    this.microtaskScheduled = false;
    if (this.rafId !== null) {
      this.cancelFrame(this.rafId);
      this.rafId = null;
    }
  }

  private scheduleMicrotask(): void {
    if (this.microtaskScheduled) return;
    this.microtaskScheduled = true;
    queueMicrotask(() => {
      this.microtaskScheduled = false;
      const changed = this.flushActions();
      if (changed) {
        this.scheduleRender();
      }
    });
  }

  private flushActions(): boolean {
    if (this.pendingActions.length === 0) return false;
    const merged = coalesce(this.pendingActions);
    this.pendingActions = [];
    if (!this.perfTracker) {
      return this.applyActions(merged);
    }
    return this.perfTracker.measure('reduce', () => this.applyActions(merged));
  }

  private scheduleRender(): void {
    if (this.paused || this.rafId !== null) return;
    this.rafId = this.requestFrame(() => {
      this.rafId = null;
      if (!this.paused) {
        if (!this.perfTracker) {
          this.render();
          return;
        }
        this.perfTracker.measure('render', () => this.render());
      }
    });
  }
}
