export class PanQuantizer {
  private remainderPx = 0;

  reset(): void {
    this.remainderPx = 0;
  }

  consume(deltaPx: number, pxPerBar: number): number {
    if (!Number.isFinite(deltaPx) || !Number.isFinite(pxPerBar) || pxPerBar <= 0) {
      return 0;
    }

    const accumulatedPx = this.remainderPx + deltaPx;
    const wholeBars = accumulatedPx >= 0
      ? Math.floor(accumulatedPx / pxPerBar)
      : Math.ceil(accumulatedPx / pxPerBar);
    this.remainderPx = accumulatedPx - wholeBars * pxPerBar;
    return wholeBars;
  }

  getRemainderPx(): number {
    return this.remainderPx;
  }

  getRemainderBars(pxPerBar: number): number {
    if (!Number.isFinite(pxPerBar) || pxPerBar <= 0) {
      return 0;
    }
    return this.remainderPx / pxPerBar;
  }
}