import type { OhlcvPoint } from '../core/types';
import type {
  IndicatorDefinition,
  IndicatorResult,
  IndicatorValue,
  MultiSeriesOutput,
} from '../core/indicatorTypes';
import { SCHEMA_VERSION } from '../core/indicatorTypes';
import type { IndicatorRegistry } from '../core/indicators';

const ok = (value: MultiSeriesOutput): IndicatorResult<MultiSeriesOutput> => ({ ok: true, value });
const fail = (message: string): IndicatorResult<MultiSeriesOutput> => ({
  ok: false,
  error: { code: 'COMPUTATION_ERROR', message },
});

type SmaState = {
  window: number[];
  sum: number;
};

type EmaState = {
  last: number;
  index: number;
};

export const SMA: IndicatorDefinition<{ period: number }, OhlcvPoint> = {
  schemaVersion: SCHEMA_VERSION,
  id: 'sma',
  name: 'SMA',
  nameKey: 'indicator.sma.name',
  category: 'trend',
  pane: 'main',
  outputs: [{ name: 'sma', color: '#4ECDC4', style: 'line', lineWidth: 1, zLayer: 30 }],
  params: {
    period: { type: 'number', default: 20, label: 'Period', min: 2, max: 200 },
  },
  complexity: { time: 'O(n)', space: 'O(n)' },
  warmupPeriod: ({ period }) => period - 1,
  calculate(data, { period }) {
    try {
      const sma: IndicatorValue[] = [];
      let sum = 0;
      for (let i = 0; i < data.length; i++) {
        sum += data[i].close;
        if (i >= period) sum -= data[i - period].close;
        if (i < period - 1) {
          sma.push(null);
        } else {
          sma.push(sum / period);
        }
      }
      return ok({ sma });
    } catch (e) {
      return fail(String(e));
    }
  },
  update(prevState, newBar, { period }) {
    try {
      if (!Number.isFinite(period) || period < 2) {
        return {
          ok: false,
          error: { code: 'INVALID_PARAMS', message: 'SMA period must be >= 2' },
        };
      }
      const state = prevState as SmaState;
      if (!state || !Array.isArray(state.window) || !Number.isFinite(state.sum)) {
        return {
          ok: false,
          error: { code: 'COMPUTATION_ERROR', message: 'SMA incremental state missing' },
        };
      }

      const nextWindow = state.window.slice();
      let nextSum = state.sum;
      nextWindow.push(newBar.close);
      nextSum += newBar.close;

      if (nextWindow.length > period) {
        const removed = nextWindow.shift();
        if (removed != null) nextSum -= removed;
      }

      const value = nextWindow.length < period ? null : nextSum / period;
      return {
        ok: true,
        value: {
          state: { window: nextWindow, sum: nextSum },
          values: { sma: value },
        },
      };
    } catch (e) {
      return {
        ok: false,
        error: { code: 'COMPUTATION_ERROR', message: String(e) },
      };
    }
  },
  // Brute-force wgslSource removed. SMA is computed via sliding-window O(n) kernel
  // (Rust WASM path: compute_sma in crates/mochart-wasm-new/src/indicators.rs).
};

export const EMA: IndicatorDefinition<{ period: number }, OhlcvPoint> = {
  schemaVersion: SCHEMA_VERSION,
  id: 'ema',
  name: 'EMA',
  nameKey: 'indicator.ema.name',
  category: 'trend',
  pane: 'main',
  outputs: [{ name: 'ema', color: '#FFB703', style: 'line', lineWidth: 1, zLayer: 30 }],
  params: {
    period: { type: 'number', default: 20, label: 'Period', min: 2, max: 200 },
  },
  complexity: { time: 'O(n)', space: 'O(n)' },
  warmupPeriod: ({ period }) => period - 1,
  calculate(data, { period }) {
    try {
      const ema: IndicatorValue[] = [];
      const k = 2 / (period + 1);
      for (let i = 0; i < data.length; i++) {
        if (i === 0) {
          ema.push(data[i].close);
          continue;
        }
        const prev = ema[i - 1] ?? data[i - 1].close;
        ema.push(data[i].close * k + (prev as number) * (1 - k));
      }
      for (let i = 0; i < period - 1; i++) {
        ema[i] = null;
      }
      return ok({ ema });
    } catch (e) {
      return fail(String(e));
    }
  },
  update(prevState, newBar, { period }) {
    try {
      if (!Number.isFinite(period) || period < 2) {
        return {
          ok: false,
          error: { code: 'INVALID_PARAMS', message: 'EMA period must be >= 2' },
        };
      }
      const state = prevState as EmaState;
      if (!state || !Number.isFinite(state.last) || !Number.isFinite(state.index)) {
        return {
          ok: false,
          error: { code: 'COMPUTATION_ERROR', message: 'EMA incremental state missing' },
        };
      }

      const k = 2 / (period + 1);
      const nextIndex = state.index + 1;
      const nextEma = newBar.close * k + state.last * (1 - k);
      const value = nextIndex < period - 1 ? null : nextEma;

      return {
        ok: true,
        value: {
          state: { last: nextEma, index: nextIndex },
          values: { ema: value },
        },
      };
    } catch (e) {
      return {
        ok: false,
        error: { code: 'COMPUTATION_ERROR', message: String(e) },
      };
    }
  },
  // R9-3: wgslSource removed — EMA is inherently sequential (Category C).
  // GPU @workgroup_size(1) is slower than CPU. Use WASM SIMD (M1) or TS fallback.
};

export const BollingerBands: IndicatorDefinition<{ period: number; stdDev: number }, OhlcvPoint> = {
  schemaVersion: SCHEMA_VERSION,
  id: 'bb',
  nameKey: 'indicator.bb.name',
  name: 'Bollinger Bands',
  category: 'volatility',
  pane: 'main',
  outputs: [
    { name: 'upper', color: '#2196F3', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 'middle', color: '#9E9E9E', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 'lower', color: '#2196F3', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 'fill', color: 'rgba(33,150,243,0.1)', style: 'band', fillTo: 'lower', zLayer: 10 },
  ],
  params: {
    period: { type: 'number', default: 20, label: 'Period', min: 5, max: 100 },
    stdDev: { type: 'number', default: 2.0, label: 'Std Dev', min: 0.5, max: 4.0, step: 0.1 },
  },
  complexity: { time: 'O(n)', space: 'O(n)' },
  warmupPeriod: ({ period }) => period - 1,
  calculate(data, { period, stdDev }) {
    try {
      // Sliding-window running sum and running sum of squares to avoid allocations per index
      const upper: IndicatorValue[] = new Array(data.length);
      const middle: IndicatorValue[] = new Array(data.length);
      const lower: IndicatorValue[] = new Array(data.length);

      if (period <= 0) {
        for (let i = 0; i < data.length; i++) {
          upper[i] = middle[i] = lower[i] = null;
        }
        return ok({ upper, middle, lower, fill: upper });
      }

      let sum = 0;
      let sumSq = 0;
      // Pre-fill first (period-1) entries as null
      for (let i = 0; i < Math.min(period - 1, data.length); i++) {
        const v = data[i].close;
        sum += v;
        sumSq += v * v;
        upper[i] = middle[i] = lower[i] = null;
      }

      // Use simple array as ring buffer for values in window (size = period)
      const window: number[] = new Array(period);
      let wIndex = 0;
      // fill window with first (period-1) values
      for (let i = 0; i < period - 1 && i < data.length; i++) {
        window[i] = data[i].close;
      }

      for (let i = period - 1; i < data.length; i++) {
        const v = data[i].close;
        // add new
        sum += v;
        sumSq += v * v;
        // push into ring buffer
        const evicted = window[wIndex];
        window[wIndex] = v;
        wIndex = (wIndex + 1) % period;

        if (i >= period) {
          // subtract evicted (only valid when window was full previously)
          if (Number.isFinite(evicted)) {
            sum -= evicted;
            sumSq -= evicted * evicted;
          }
        }

        const sma = sum / period;
        const variance = Math.max(0, sumSq / period - sma * sma);
        const std = Math.sqrt(variance);
        middle[i] = sma;
        upper[i] = sma + stdDev * std;
        lower[i] = sma - stdDev * std;
      }

      return ok({ upper, middle, lower, fill: upper });
    } catch (e) {
      return fail(String(e));
    }
  },
  // Brute-force wgslSource removed. BB is computed via dual-pass sliding-window O(n) kernel
  // (Rust WASM path: compute_bb planned in crates/mochart-wasm-new/src/indicators.rs).
};

export const Volume: IndicatorDefinition<{ maPeriod: number }, OhlcvPoint> = {
  schemaVersion: SCHEMA_VERSION,
  id: 'volume',
  nameKey: 'indicator.volume.name',
  name: 'Volume',
  category: 'volume',
  pane: 'sub1',
  outputs: [
    { name: 'volume', color: '#90CAF9', style: 'bar', opacity: 0.8, zLayer: 20 },
    { name: 'volumeMA', color: '#1565C0', style: 'line', lineWidth: 1, zLayer: 30 },
  ],
  params: {
    maPeriod: { type: 'number', default: 20, label: 'MA Period', min: 5, max: 50 },
  },
  complexity: { time: 'O(n)', space: 'O(n)' },
  warmupPeriod: ({ maPeriod }) => maPeriod - 1,
  calculate(data, { maPeriod }) {
    try {
      const volume: IndicatorValue[] = new Array(data.length);
      const volumeMA: IndicatorValue[] = new Array(data.length);
      if (maPeriod <= 0) {
        for (let i = 0; i < data.length; i++) {
          volume[i] = data[i].volume;
          volumeMA[i] = null;
        }
        return ok({ volume, volumeMA });
      }

      let sum = 0;
      // pre-fill first (maPeriod-1)
      for (let i = 0; i < Math.min(maPeriod - 1, data.length); i++) {
        const v = data[i].volume;
        volume[i] = v;
        sum += v;
        volumeMA[i] = null;
      }

      const window: number[] = new Array(maPeriod);
      let wIndex = 0;
      for (let i = 0; i < maPeriod - 1 && i < data.length; i++) window[i] = data[i].volume;

      for (let i = maPeriod - 1; i < data.length; i++) {
        const v = data[i].volume;
        volume[i] = v;
        sum += v;
        const evicted = window[wIndex];
        window[wIndex] = v;
        wIndex = (wIndex + 1) % maPeriod;
        if (i >= maPeriod) {
          if (Number.isFinite(evicted)) sum -= evicted;
        }
        volumeMA[i] = sum / maPeriod;
      }

      return ok({ volume, volumeMA });
    } catch (e) {
      return fail(String(e));
    }
  },
};

export const PivotPoints: IndicatorDefinition<{}, OhlcvPoint> = {
  schemaVersion: SCHEMA_VERSION,
  nameKey: 'indicator.pivot_points.name',
  id: 'pivot_points',
  name: 'Pivot Points',
  category: 'trend',
  pane: 'main',
  outputs: [
    { name: 'pivot', color: '#607D8B', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 'r1', color: '#8BC34A', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 's1', color: '#F44336', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 'r2', color: '#4CAF50', style: 'line', lineWidth: 1, zLayer: 30 },
    { name: 's2', color: '#E57373', style: 'line', lineWidth: 1, zLayer: 30 },
  ],
  params: {},
  complexity: { time: 'O(n)', space: 'O(n)' },
  warmupPeriod: () => 1,
  calculate(data) {
    try {
      const pivot: IndicatorValue[] = [];
      const r1: IndicatorValue[] = [];
      const s1: IndicatorValue[] = [];
      const r2: IndicatorValue[] = [];
      const s2: IndicatorValue[] = [];
      for (let i = 0; i < data.length; i++) {
        if (i === 0) {
          pivot.push(null);
          r1.push(null);
          s1.push(null);
          r2.push(null);
          s2.push(null);
          continue;
        }
        const prev = data[i - 1];
        const p = (prev.high + prev.low + prev.close) / 3;
        const r1v = 2 * p - prev.low;
        const s1v = 2 * p - prev.high;
        const r2v = p + (prev.high - prev.low);
        const s2v = p - (prev.high - prev.low);
        pivot.push(p);
        r1.push(r1v);
        s1.push(s1v);
        r2.push(r2v);
        s2.push(s2v);
      }
      return ok({ pivot, r1, s1, r2, s2 });
    } catch (e) {
      return fail(String(e));
    }
  },
};

export const Phase1Indicators = [Volume, SMA, EMA, BollingerBands, PivotPoints] as const;

export const registerPhase1Indicators = (registry: IndicatorRegistry): void => {
  Phase1Indicators.forEach((indicator) => registry.register(indicator as IndicatorDefinition<any, any>));
};
