export type PerfMetricName = 'reduce' | 'render' | 'draw' | 'upload';

export type PerfMetricStats = Readonly<{
  count: number;
  totalMs: number;
  avgMs: number;
  maxMs: number;
  lastMs: number;
}>;

export type PerfSnapshot = Readonly<Record<PerfMetricName, PerfMetricStats>>;

type MutablePerfStats = {
  count: number;
  totalMs: number;
  maxMs: number;
  lastMs: number;
};

function createZeroStats(): MutablePerfStats {
  return { count: 0, totalMs: 0, maxMs: 0, lastMs: 0 };
}

export class PerformanceTracker {
  private enabled = true;
  private sequence = 0;
  private stats: Record<PerfMetricName, MutablePerfStats> = {
    reduce: createZeroStats(),
    render: createZeroStats(),
    draw: createZeroStats(),
    upload: createZeroStats(),
  };

  setEnabled(enabled: boolean): void {
    this.enabled = enabled;
  }

  isEnabled(): boolean {
    return this.enabled;
  }

  reset(): void {
    this.stats = {
      reduce: createZeroStats(),
      render: createZeroStats(),
      draw: createZeroStats(),
      upload: createZeroStats(),
    };
  }

  measure<T>(metric: PerfMetricName, fn: () => T): T {
    if (!this.enabled) {
      return fn();
    }

    const perf = typeof performance !== 'undefined' ? performance : null;
    const startMark = perf ? `mochart:${metric}:start:${this.sequence}` : '';
    const endMark = perf ? `mochart:${metric}:end:${this.sequence}` : '';
    const measureName = perf ? `mochart:${metric}:measure:${this.sequence}` : '';
    this.sequence += 1;

    if (!perf) {
      const start = Date.now();
      const result = fn();
      this.record(metric, Date.now() - start);
      return result;
    }

    perf.mark(startMark);
    try {
      return fn();
    } finally {
      perf.mark(endMark);
      perf.measure(measureName, startMark, endMark);
      const entries = perf.getEntriesByName(measureName, 'measure');
      const duration = entries.length > 0 ? entries[entries.length - 1].duration : 0;
      this.record(metric, duration);
      perf.clearMeasures(measureName);
      perf.clearMarks(startMark);
      perf.clearMarks(endMark);
    }
  }

  getSnapshot(): PerfSnapshot {
    return {
      reduce: this.buildReadonlyStats(this.stats.reduce),
      render: this.buildReadonlyStats(this.stats.render),
      draw: this.buildReadonlyStats(this.stats.draw),
      upload: this.buildReadonlyStats(this.stats.upload),
    };
  }

  private buildReadonlyStats(stats: MutablePerfStats): PerfMetricStats {
    const avgMs = stats.count > 0 ? stats.totalMs / stats.count : 0;
    return {
      count: stats.count,
      totalMs: stats.totalMs,
      avgMs,
      maxMs: stats.maxMs,
      lastMs: stats.lastMs,
    };
  }

  private record(metric: PerfMetricName, durationMs: number): void {
    if (!Number.isFinite(durationMs)) return;
    const target = this.stats[metric];
    target.count += 1;
    target.totalMs += durationMs;
    target.lastMs = durationMs;
    if (durationMs > target.maxMs) {
      target.maxMs = durationMs;
    }
  }
}

export function createEmptyPerfSnapshot(): PerfSnapshot {
  const zero = Object.freeze({ count: 0, totalMs: 0, avgMs: 0, maxMs: 0, lastMs: 0 });
  return Object.freeze({
    reduce: zero,
    render: zero,
    draw: zero,
    upload: zero,
  });
}
