// Lightweight TypedArray pool to avoid per-frame allocations on hot paths.
type PoolKey = `${string}:${number}`;

const float32Pools = new Map<number, Float32Array[]>();
const float64Pools = new Map<number, Float64Array[]>();
const uint16Pools = new Map<number, Uint16Array[]>();

export function getPooledFloat32(size: number): Float32Array {
  const bucket = float32Pools.get(size);
  if (bucket && bucket.length > 0) return bucket.pop()!;
  return new Float32Array(size);
}

export function releasePooledFloat32(buf: Float32Array) {
  const size = buf.length;
  const bucket = float32Pools.get(size) || [];
  // zeroing is optional; callers should overwrite
  bucket.push(buf);
  float32Pools.set(size, bucket);
}

export function getPooledFloat64(size: number): Float64Array {
  const bucket = float64Pools.get(size);
  if (bucket && bucket.length > 0) return bucket.pop()!;
  return new Float64Array(size);
}

export function releasePooledFloat64(buf: Float64Array) {
  const size = buf.length;
  const bucket = float64Pools.get(size) || [];
  bucket.push(buf);
  float64Pools.set(size, bucket);
}

export function getPooledUint16(size: number): Uint16Array {
  const bucket = uint16Pools.get(size);
  if (bucket && bucket.length > 0) return bucket.pop()!;
  return new Uint16Array(size);
}

export function releasePooledUint16(buf: Uint16Array) {
  const size = buf.length;
  const bucket = uint16Pools.get(size) || [];
  bucket.push(buf);
  uint16Pools.set(size, bucket);
}

export function clearPools() {
  float32Pools.clear();
  float64Pools.clear();
  uint16Pools.clear();
}
