// src/core/store/types.ts

/**
 * ChartState: The single source of truth for the chart's state.
 * All properties are Readonly to ensure immutability.
 */
export type ChartState = Readonly<{
  /** Viewport state: What part of the data is currently visible */
  viewport: Readonly<{
    /** Index of the first visible bar in the dataset */
    startIndex: number;
    /** Number of bars currently visible */
    visibleCount: number;
    /** Right margin in pixels (only active when scrolled to the end) */
    rightMargin: number;
  }>;

  /** Layout state: Physical dimensions and device characteristics */
  layout: Readonly<{
    width: number;
    height: number;
    dpr: number;
  }>;

  /** Interaction state: Current user interaction details */
  interaction: Readonly<{
    /** Current pointer position (if hovering) */
    hover: Readonly<{ x: number; y: number }> | null;
    /** Drag state (if dragging) */
    drag: Readonly<{
      startX: number;
      startStartIndex: number;
    }> | null;
    /** Pinch zoom state (if pinching) */
    pinch: Readonly<{
      startScale: number;
      centerX: number;
      startVisibleCount: number;
    }> | null;
  }>;

  /** Data meta-state (Actual data is stored in SeriesStore for performance, this tracks metadata/versions) */
  data: Readonly<{
    /** Total number of bars in the primary dataset */
    totalBars: number;
    /** Version counter to detect data updates */
    version: number;
  }>;
}>;

/**
 * Initial state of the chart
 */
export const REQUIRED_INITIAL_STATE: ChartState = {
  viewport: {
    startIndex: 0,
    visibleCount: 100,
    rightMargin: 50,
  },
  layout: {
    width: 800,
    height: 400,
    dpr: 1,
  },
  interaction: {
    hover: null,
    drag: null,
    pinch: null,
  },
  data: {
    totalBars: 0,
    version: 0,
  },
};
