type FrameRequest = number | ReturnType<typeof setTimeout>;

export class FrameAlignedSampler<T> {
  private latestBySeriesId = new Map<string, T>();
  private pendingBySeriesId = new Map<string, T>();
  private frameRequest: FrameRequest | null = null;

  constructor(
    private readonly onEmit: (seriesId: string, value: T) => void,
  ) {}

  push(seriesId: string, value: T): void {
    this.latestBySeriesId.set(seriesId, value);
    this.scheduleEmit();
  }

  size(): number {
    return this.latestBySeriesId.size;
  }

  clear(): void {
    this.latestBySeriesId.clear();
  }

  destroy(): void {
    if (this.frameRequest != null) {
      if (typeof requestAnimationFrame === 'function' && typeof cancelAnimationFrame === 'function') {
        cancelAnimationFrame(this.frameRequest as number);
      } else {
        clearTimeout(this.frameRequest as ReturnType<typeof setTimeout>);
      }
      this.frameRequest = null;
    }
    this.latestBySeriesId.clear();
  }

  private scheduleEmit(): void {
    if (this.frameRequest != null) return;

    if (typeof requestAnimationFrame === 'function') {
      this.frameRequest = requestAnimationFrame(() => {
        this.frameRequest = null;
        this.flush();
      });
      return;
    }

    this.frameRequest = setTimeout(() => {
      this.frameRequest = null;
      this.flush();
    }, 16);
  }

  private flush(): void {
    if (this.latestBySeriesId.size === 0) return;
    const pending = this.pendingBySeriesId;
    pending.clear();
    for (const [seriesId, value] of this.latestBySeriesId) {
      pending.set(seriesId, value);
    }
    this.latestBySeriesId.clear();

    for (const [seriesId, value] of pending) {
      this.onEmit(seriesId, value);
    }
    pending.clear();
  }
}