/**
 * Canonical candle layout computation — single source of truth for all renderers.
 *
 * Canvas 2D consumes this pixel-space specification directly:
 *   - Canvas 2D: use stepPx / bodyWidthPx directly
 *   - Rust WASM WebGPU path: halfBodyNdc = bodyWidthPx / plotWidthPx
 *
 * This eliminates the previous divergence where each renderer computed its
 * own candle widths, padding, and visible window independently.
 */

// ── Shared Constants ──

/** Body width as a fraction of step width (70%). */
export const BODY_WIDTH_RATIO = 0.5;
/** Minimum candle body width in CSS pixels. */
export const MIN_BODY_WIDTH_PX = 1;
/** Maximum candle body width in CSS pixels. */
export const MAX_BODY_WIDTH_PX = 40;
/** Wick width in CSS pixels (thin line). */
export const WICK_WIDTH_PX = 1;
/** Default vertical padding ratio (fraction of visible price range). */
export const DEFAULT_PADDING_RATIO = 0.05;
/** Default minimum vertical padding in CSS pixels. */
export const DEFAULT_MIN_PADDING_PX = 6;

// ── Visible Window ──

export interface VisibleWindow {
  /** First data index (inclusive). */
  start: number;
  /** Last data index (exclusive). */
  end: number;
  /** Requested visible bar count (may exceed available data). */
  visibleCount: number;
  /** Total slot count including right margin bars. */
  totalSlots: number;
}

/**
 * Resolve the visible data window from viewport parameters.
 * Shared by all renderers (Canvas 2D, Rust WASM WebGPU).
 *
 * Canvas has its own richer version (fractional startIndex, maxVisibleBars)
 * but the core algorithm is identical.
 */
export function resolveVisibleWindow(
  dataLength: number,
  startIndex?: number,
  visibleCount?: number,
  rightMarginBars?: number,
): VisibleWindow {
  const maxLength = Math.max(0, dataLength | 0);
  const requestedStart = Math.floor(startIndex ?? 0);
  const start = Math.max(0, Math.min(maxLength, requestedStart));

  const vc = typeof visibleCount === 'number'
    ? Math.max(0, Math.floor(visibleCount))
    : Math.max(0, maxLength - start);

  const end = Math.max(start, Math.min(maxLength, start + vc));
  const rightMargin = Math.max(0, Math.floor(rightMarginBars ?? 0));
  const totalSlots = Math.max(1, vc + rightMargin);

  return { start, end, visibleCount: vc, totalSlots };
}

// ── Price Range ──

export interface PaddedPriceRange {
  /** Padded minimum price. */
  min: number;
  /** Padded maximum price. */
  max: number;
  /** Padded price range (max - min), guaranteed > 0. */
  range: number;
}

/**
 * Apply visual padding to a raw price range so bars don't touch edges.
 * Identical formula for all renderers.
 */
export function computePaddedPriceRange(
  rawMin: number,
  rawMax: number,
  plotHeightPx: number,
  paddingRatio = DEFAULT_PADDING_RATIO,
  minPaddingPx = DEFAULT_MIN_PADDING_PX,
): PaddedPriceRange {
  if (!isFinite(rawMin) || !isFinite(rawMax)) {
    return { min: 0, max: 1, range: 1 };
  }
  const rawRange = Math.max(rawMax - rawMin, Math.max(1e-9, Math.abs(rawMax) * 0.001));
  const basePad = rawRange * paddingRatio;
  const minPaddingPrice = (rawRange / Math.max(1, plotHeightPx)) * minPaddingPx;
  const pad = Math.max(basePad, minPaddingPrice);
  const min = rawMin - pad;
  const max = rawMax + pad;
  return { min, max, range: max - min || 1 };
}

// ── Candle Metrics ──

export interface CandleMetrics {
  /** Distance between bar centers in CSS pixels. */
  stepPx: number;
  /** Body width in CSS pixels (clamped to [MIN, MAX]). */
  bodyWidthPx: number;
  /** Wick width in CSS pixels. */
  wickWidthPx: number;
}

/**
 * Compute candle sizing in CSS pixels.
 * GPU renderers convert: halfBodyNdc = bodyWidthPx / plotWidthPx.
 */
export function computeCandleMetrics(totalSlots: number, plotWidthPx: number): CandleMetrics {
  const stepPx = plotWidthPx / Math.max(1, totalSlots - 1);
  const bodyWidthPx = Math.max(
    MIN_BODY_WIDTH_PX,
    Math.min(Math.floor(stepPx * BODY_WIDTH_RATIO), MAX_BODY_WIDTH_PX),
  );
  return { stepPx, bodyWidthPx, wickWidthPx: WICK_WIDTH_PX };
}

// ── Layout ──

export interface SharedRendererLayout {
  gutterLeft: number;
  gutterTop: number;
  gutterRight: number;
  xAxisHeight: number;
  plotX: number;
  plotY: number;
  plotW: number;
  plotH: number;
}

/**
 * Shared layout calculation for all renderers to ensure consistent alignment.
 */
export function computeRendererLayout(
  canvasWidth: number,
  canvasHeight: number,
  options?: {
    yAxisGutterPx?: number;
    xAxisHeightPx?: number;
  }
): SharedRendererLayout {
  const gutterLeft = options?.yAxisGutterPx ?? 56;
  const gutterRight = 8;
  const gutterTop = 8;
  const xAxisHeight = options?.xAxisHeightPx ?? 26;
  
  const plotX = gutterLeft;
  const plotY = gutterTop;
  const plotW = Math.max(1, canvasWidth - gutterLeft - gutterRight);
  // -6px aesthetic padding at bottom
  const plotH = Math.max(1, canvasHeight - gutterTop - xAxisHeight - 6);

  return {
    gutterLeft,
    gutterTop,
    gutterRight,
    xAxisHeight,
    plotX,
    plotY,
    plotW,
    plotH
  };
}
