import type { OhlcvPoint } from '../../core/types';
import { CanvasRenderer } from '../canvas/canvasRenderer';
import type {
  MapClientToDataResult,
  OverlayCommand,
  RenderSnapshot,
  RendererLayout,
  RendererViewportOptions,
  ViewportRenderer,
} from '../renderer';
import type { ColumnarOHLCV } from '../../data/columnarStore';
import type {
  WorkerMessageToRender,
  WorkerRenderPayload,
  WorkerSharedRenderPayload,
  ColumnarSliceData,
  WorkerHudOverlaySnapshot,
} from './protocol';
import {
  WORKER_RENDER_SCHEMA_VERSION,
  WORKER_HUD_OVERLAY_SCHEMA_VERSION,
  normalizeWorkerHudOverlaySnapshot,
} from './protocol';
import { SharedOhlcvFrameBuffer } from './sharedFrameBuffer';

type ResolvedPrimary = {
  data: ReadonlyArray<OhlcvPoint> | ColumnarSliceData;
  startIndex: number;
};

export interface WorkerCanvasRendererOptions {
  workerUrl?: string | URL;
  sharedWorker?: Worker;
  onStateChange?: (mode: 'fallback' | 'msg' | 'shared') => void;
}

export class WorkerCanvasRenderer implements ViewportRenderer {
  private static nextChartId = 1;

  private readonly canvas: HTMLCanvasElement;
  private readonly helperRenderer: CanvasRenderer;
  private readonly helperCanvas: HTMLCanvasElement;
  private readonly workerUrlOverride: string | URL | undefined;
  private readonly injectedWorker: Worker | undefined;
  private readonly onStateChange: ((mode: 'fallback' | 'msg' | 'shared') => void) | undefined;
  private readonly chartId: number;
  private ownsWorker = false;
  private fallbackRenderer: CanvasRenderer | null = null;
  private worker: Worker | null = null;
  private lastPayload: WorkerRenderPayload | null = null;
  private sharedFrameBuffer: SharedOhlcvFrameBuffer | null = null;
  private sharedGeneration = -1;
  private lastState: 'fallback' | 'msg' | 'shared' | null = null;
  private awaitingFrame = false;
  private awaitingFrameTimer: ReturnType<typeof setTimeout> | null = null;
  private lastOverlayRevisionSent = -1;

  constructor(canvas: HTMLCanvasElement, options?: WorkerCanvasRendererOptions) {
    this.canvas = canvas;
    this.helperCanvas = canvas.ownerDocument ? canvas.ownerDocument.createElement('canvas') : canvas;
    this.helperRenderer = new CanvasRenderer(this.helperCanvas);
    this.workerUrlOverride = options?.workerUrl;
    this.injectedWorker = options?.sharedWorker;
    this.onStateChange = options?.onStateChange;
    this.chartId = WorkerCanvasRenderer.nextChartId++;

    if (!this.tryInitializeWorker()) {
      this.fallbackRenderer = new CanvasRenderer(canvas);
      this.publishState('fallback');
      return;
    }

    this.publishState(this.sharedFrameBuffer ? 'shared' : 'msg');
  }

  render(snapshot: RenderSnapshot): void {
    this.syncHelperCanvasSize(snapshot.layout.width, snapshot.layout.height, snapshot.layout.dpr);

    const payload = this.toWorkerPayload(snapshot);
    this.lastPayload = payload;

    if (this.fallbackRenderer) {
      this.fallbackRenderer.render(snapshot);
      return;
    }

    if ((snapshot.overlayRevision ?? 0) !== this.lastOverlayRevisionSent) {
      const primitives = snapshot.overlayPrimitives ?? [];
      this.postMessage({
        type: 'ann_bulk', chartId: this.chartId,
        payload: {
          revision: snapshot.overlayRevision ?? 0,
          primitives,
        },
      });
      this.lastOverlayRevisionSent = snapshot.overlayRevision ?? 0;
    }

    const sharedPayload = this.toSharedWorkerPayload(snapshot);
    if (sharedPayload) {
      this.postMessage({ type: 'renderShared', chartId: this.chartId, payload: sharedPayload });
      return;
    }

    // Do not flood worker: if a frame is outstanding, just keep latest payload and return.
    if (this.awaitingFrame) return;

    // If payload.data is a Columnar slice, copy into compact transferable buffers
    // to avoid structured-clone of many views or detaching shared backing buffers.
    const data = (payload as any).data as any;
    if (data && typeof data === 'object' && data.time instanceof Float64Array && data.length > 0) {
      const len = data.length | 0;
      const timeBuf = new Float64Array(len);
      const openBuf = new Float32Array(len);
      const highBuf = new Float32Array(len);
      const lowBuf = new Float32Array(len);
      const closeBuf = new Float32Array(len);
      const volBuf = new Float32Array(len);

      timeBuf.set(data.time.subarray(0, len));
      openBuf.set(data.open.subarray(0, len));
      highBuf.set(data.high.subarray(0, len));
      lowBuf.set(data.low.subarray(0, len));
      closeBuf.set(data.close.subarray(0, len));
      volBuf.set(data.volume.subarray(0, len));

      const transferablePayload = {
        ...payload,
        data: {
          time: timeBuf,
          open: openBuf,
          high: highBuf,
          low: lowBuf,
          close: closeBuf,
          volume: volBuf,
          length: len,
        },
      };

      const transfers = [
        timeBuf.buffer,
        openBuf.buffer,
        highBuf.buffer,
        lowBuf.buffer,
        closeBuf.buffer,
        volBuf.buffer,
      ];

      this.postMessage({ type: 'render', chartId: this.chartId, payload: transferablePayload }, transfers);
      this.awaitingFrame = true;
      this.armAwaitingFrameWatchdog();
      return;
    }

    this.postMessage({ type: 'render', chartId: this.chartId, payload });
    this.awaitingFrame = true;
    this.armAwaitingFrameWatchdog();
  }

  renderOverlay(snapshot: RenderSnapshot, command: OverlayCommand): void {
    if (this.fallbackRenderer) {
      this.fallbackRenderer.renderOverlay?.(snapshot, command);
      return;
    }

    if (command.type !== 'crosshair') return;
    this.postMessage({
      type: 'overlay', chartId: this.chartId,
      payload: {
        clientX: command.clientX,
        clientY: command.clientY,
      },
    });
  }

  clearOverlay(snapshot: RenderSnapshot): void {
    if (this.fallbackRenderer) {
      this.fallbackRenderer.clearOverlay?.(snapshot);
      return;
    }

    this.postMessage({ type: 'clearOverlay', chartId: this.chartId });
  }

  clear(): void {
    if (this.fallbackRenderer) {
      this.fallbackRenderer.clear?.();
      return;
    }
    this.postMessage({ type: 'ann_clear', chartId: this.chartId });
  }

  drawSeries(seriesId: string, data: ReadonlyArray<unknown> | ColumnarOHLCV, options?: RendererViewportOptions): void {
    if (this.fallbackRenderer) {
      this.fallbackRenderer.drawSeries(seriesId, data, options);
      return;
    }

    this.helperRenderer.drawSeries(seriesId, data, options);
  }

  getLayout(data: ReadonlyArray<unknown> | ColumnarOHLCV, options?: RendererViewportOptions): RendererLayout {
    return this.helperRenderer.getLayout(data, options);
  }

  mapClientToData(
    clientX: number,
    clientY: number,
    data: ReadonlyArray<unknown> | ColumnarOHLCV,
    options?: RendererViewportOptions,
  ): MapClientToDataResult | null {
    return this.helperRenderer.mapClientToData(clientX, clientY, data, options);
  }

  hitTest(
    clientX: number,
    clientY: number,
    data: ReadonlyArray<unknown> | ColumnarOHLCV,
    options?: RendererViewportOptions,
  ): MapClientToDataResult | null {
    return this.helperRenderer.hitTest(clientX, clientY, data, options);
  }

  drawCrosshairAt(
    clientX: number,
    clientY: number,
    data: ReadonlyArray<unknown> | ColumnarOHLCV,
    options?: RendererViewportOptions,
  ): void {
    if (this.fallbackRenderer) {
      this.fallbackRenderer.drawCrosshairAt(clientX, clientY, data, options);
      return;
    }

    this.postMessage({
      type: 'overlay', chartId: this.chartId,
      payload: {
        clientX,
        clientY,
      },
    });
  }

  resize(): void {
    if (this.fallbackRenderer) {
      this.fallbackRenderer.resize();
      this.syncHelperCanvasSize();
      return;
    }

    this.syncHelperCanvasSize();
    if (this.lastPayload) {
      this.postMessage({ type: 'render', chartId: this.chartId, payload: this.lastPayload });
    }
  }

  destroy(): void {
    this.postMessage({ type: 'destroy', chartId: this.chartId });
    this.clearAwaitingFrameWatchdog();
    if (this.ownsWorker) this.worker?.terminate();
    this.worker = null;
    this.fallbackRenderer?.destroy();
    this.helperRenderer.destroy();
  }

  getDebugModeLabel(): string {
    if (this.fallbackRenderer) return 'canvas (worker-fallback)';
    const shared = this.sharedFrameBuffer ? 'shared' : 'msg';
    return `canvas-worker (${shared})`;
  }

  private tryInitializeWorker(): boolean {
    if (typeof Worker === 'undefined') return false;
    if (typeof OffscreenCanvas === 'undefined') return false;

    const transferableCanvas = this.canvas as HTMLCanvasElement & {
      transferControlToOffscreen?: () => OffscreenCanvas;
    };

    if (typeof transferableCanvas.transferControlToOffscreen !== 'function') {
      return false;
    }

    try {
      const worker = this.injectedWorker ?? new Worker(this.resolveWorkerScriptUrl(), { type: 'module' });
      const offscreen = transferableCanvas.transferControlToOffscreen();
      const initMessage: WorkerMessageToRender = { type: 'init', chartId: this.chartId, canvas: offscreen };
      worker.postMessage(initMessage, [offscreen]);
      this.worker = worker;
      this.ownsWorker = this.injectedWorker == null;
      // Listen for frameDone acknowledgements to avoid flooding the worker and to keep render timing tight
      this.worker.addEventListener('message', (ev: MessageEvent) => {
        const d = ev.data as any;
        if (d && d.type === 'frameDone' && d.chartId === this.chartId) {
          this.awaitingFrame = false;
          this.clearAwaitingFrameWatchdog();
          // If there is a queued payload (lastPayload), send it immediately
          if (this.lastPayload) {
            this.postMessage({ type: 'render', chartId: this.chartId, payload: this.lastPayload });
            this.awaitingFrame = true;
            this.armAwaitingFrameWatchdog();
          }
        }
      });

      if (this.canUseSharedMemory()) {
        this.sharedFrameBuffer = new SharedOhlcvFrameBuffer(0);
        this.sharedGeneration = -1;
      }

      return true;
    } catch {
      this.worker?.terminate();
      this.worker = null;
      this.sharedFrameBuffer = null;
      this.sharedGeneration = -1;
      return false;
    }
  }

  private canUseSharedMemory(): boolean {
    if (typeof SharedArrayBuffer === 'undefined') return false;
    if (typeof Atomics === 'undefined') return false;
    if (typeof globalThis.crossOriginIsolated !== 'boolean') return false;
    return globalThis.crossOriginIsolated;
  }

  private postMessage(message: WorkerMessageToRender, transfer?: ArrayBufferLike[]): void {
    if (!this.worker) return;
    try {
      if (transfer && transfer.length > 0) {
        this.worker.postMessage(message, transfer);
      } else {
        this.worker.postMessage(message);
      }
    } catch {
      // Fallback to non-transfer postMessage if transfer fails for any reason
      try { this.worker.postMessage(message); } catch { /* swallow */ }
    }
  }

  private clearAwaitingFrameWatchdog(): void {
    if (this.awaitingFrameTimer == null) return;
    clearTimeout(this.awaitingFrameTimer);
    this.awaitingFrameTimer = null;
  }

  private armAwaitingFrameWatchdog(): void {
    this.clearAwaitingFrameWatchdog();
    this.awaitingFrameTimer = setTimeout(() => {
      // Fail-open: avoid permanent render stall when frameDone ack is dropped.
      this.awaitingFrame = false;
      this.awaitingFrameTimer = null;
    }, 120);
  }

  private resolvePrimaryData(snapshot: RenderSnapshot): ResolvedPrimary {
    const targetSeries = snapshot.primarySeriesId == null
      ? snapshot.series[0]
      : snapshot.series.find((series) => series.id === snapshot.primarySeriesId) ?? snapshot.series[0];

    if (!targetSeries) {
      return { data: [], startIndex: snapshot.viewport.startIndex };
    }

    if (targetSeries.visibleSlice) {
      const slice = targetSeries.visibleSlice;
      // Send Columnar slice directly to worker to avoid per-bar object allocations.
      // Note: structured-clone will copy typed arrays if not SharedArrayBuffer; this is still
      // preferable to allocating many small objects.
      return {
        data: {
          time: slice.time,
          open: slice.open,
          high: slice.high,
          low: slice.low,
          close: slice.close,
          volume: slice.volume,
          length: slice.length,
        },
        startIndex: Math.max(0, snapshot.viewport.startIndex - slice.globalOffset),
      };
    }

    return {
      data: (targetSeries.data ?? []) as ReadonlyArray<OhlcvPoint>,
      startIndex: snapshot.viewport.startIndex,
    };
  }

  private resolveWorkerScriptUrl(): URL {
    if (this.workerUrlOverride instanceof URL) {
      return this.workerUrlOverride;
    }

    if (typeof this.workerUrlOverride === 'string' && this.workerUrlOverride.length > 0) {
      try {
        return new URL(this.workerUrlOverride, import.meta.url);
      } catch {
      }
    }

    const moduleUrl = new URL(import.meta.url);
    if (moduleUrl.pathname.includes('/src/demo/')) {
      return new URL('/src/renderer/worker/renderWorker.ts', moduleUrl.origin);
    }
    if (moduleUrl.pathname.includes('/src/renderer/worker/')) {
      return new URL('./renderWorker.ts', import.meta.url);
    }

    return new URL('./renderWorker.js', import.meta.url);
  }

  private toWorkerPayload(snapshot: RenderSnapshot): WorkerRenderPayload {
    const resolved = this.resolvePrimaryData(snapshot);
    // When taking a slice, the worker sees a subset of data.
    // If we send only the visible slice, the worker should render from index 0 relative to that slice,
    // or we must adjust the viewport.startIndex passed to the worker.
    // The worker expects `data` to cover the range requested by `viewport`.
    // If we only send the slice, we should tell the worker that the data starts at `resolved.startIndex`.
    
    // However, the worker implementation (renderFrame) does:
    //   const start = Math.floor(payload.viewport.startIndex);
    //   data[start + i]
    // 
    // To match this, if we send a slice, we must effectively "shift" the viewport so the worker reads from 0?
    // OR, we change the protocol.
    // simpler fix for now: adjust the viewport sent to worker to be relative to the slice if we are using a slice.
    
    const isSlice = snapshot.series[0]?.visibleSlice !== undefined;
    const workerStartIndex = isSlice ? resolved.startIndex : snapshot.viewport.startIndex;
    const normalizedHud = normalizeWorkerHudOverlaySnapshot(snapshot.hudOverlay as WorkerHudOverlaySnapshot | undefined);
    const hudOverlay = normalizedHud
      ? {
          ...normalizedHud,
          version: WORKER_HUD_OVERLAY_SCHEMA_VERSION,
        }
      : undefined;

    return {
      schemaVersion: WORKER_RENDER_SCHEMA_VERSION,
      viewport: {
        startIndex: workerStartIndex,
        visibleCount: snapshot.viewport.visibleCount,
        rightMarginBars: snapshot.viewport.rightMarginBars,
      },
      layout: {
        width: snapshot.layout.width,
        height: snapshot.layout.height,
        dpr: snapshot.layout.dpr,
      },
      hudOverlay,
      data: resolved.data,
    };
  }

  private toSharedWorkerPayload(snapshot: RenderSnapshot): WorkerSharedRenderPayload | null {
    if (!this.worker || !this.sharedFrameBuffer) return null;
    this.publishState('shared');

    const resolved = this.resolvePrimaryData(snapshot);
    const startIndex = Math.max(0, Math.floor(resolved.startIndex));
    const visibleCount = Math.max(1, Math.floor(snapshot.viewport.visibleCount));
    let writeResult;
    if ((resolved.data as any)?.time instanceof Float64Array) {
      writeResult = this.sharedFrameBuffer.writeFrameFromColumnar(resolved.data as any, startIndex, visibleCount);
    } else {
      writeResult = this.sharedFrameBuffer.writeFrame(resolved.data as ReadonlyArray<OhlcvPoint>, startIndex, visibleCount);
    }

    if (writeResult.resized || this.sharedGeneration !== this.sharedFrameBuffer.getGeneration()) {
      this.sharedGeneration = this.sharedFrameBuffer.getGeneration();
      this.postMessage({
        type: 'initShared', chartId: this.chartId,
        descriptor: this.sharedFrameBuffer.getDescriptor(),
      });
    }

    const normalizedHud = normalizeWorkerHudOverlaySnapshot(snapshot.hudOverlay as WorkerHudOverlaySnapshot | undefined);
    const hudOverlay = normalizedHud
      ? {
          ...normalizedHud,
          version: WORKER_HUD_OVERLAY_SCHEMA_VERSION,
        }
      : undefined;

    return {
      schemaVersion: WORKER_RENDER_SCHEMA_VERSION,
      viewport: {
        startIndex: resolved.startIndex,
        visibleCount: snapshot.viewport.visibleCount,
        rightMarginBars: snapshot.viewport.rightMarginBars,
      },
      layout: {
        width: snapshot.layout.width,
        height: snapshot.layout.height,
        dpr: snapshot.layout.dpr,
      },
      hudOverlay,
      frameId: writeResult.frameId,
    };
  }

  private publishState(mode: 'fallback' | 'msg' | 'shared'): void {
    if (this.lastState === mode) return;
    this.lastState = mode;
    this.onStateChange?.(mode);
  }

  private syncHelperCanvasSize(width?: number, height?: number, dpr?: number): void {
    const resolvedDpr = dpr ?? (typeof window !== 'undefined' ? (window.devicePixelRatio || 1) : 1);
    const resolvedWidth = Math.max(1, Math.floor(width ?? this.canvas.clientWidth ?? this.canvas.width ?? 800));
    const resolvedHeight = Math.max(1, Math.floor(height ?? this.canvas.clientHeight ?? this.canvas.height ?? 600));

    this.helperCanvas.style.width = `${resolvedWidth}px`;
    this.helperCanvas.style.height = `${resolvedHeight}px`;
    this.helperCanvas.width = Math.floor(resolvedWidth * resolvedDpr);
    this.helperCanvas.height = Math.floor(resolvedHeight * resolvedDpr);
    this.helperRenderer.resize();
  }
}
