import { ChartStore } from './store/store';
import type { Action } from './store/actions';
import { ActionType } from './store/actions';
import { RenderScheduler } from './scheduler';
import { PerformanceTracker, type PerfSnapshot } from './perf';
import type {
  OverlayCommand,
  RendererLayout,
  MapClientToDataResult,
  RendererViewportOptions,
  HudOverlaySnapshot,
  OverlayRenderPrimitive,
} from '../renderer/renderer';
import type { OhlcvPoint, IndicatorInstance } from './types';
import { IndicatorComputeStore } from './store/indicatorComputeStore';
import { InMemoryIndicatorRegistry } from './indicators';
import { registerPhase1Indicators } from '../indicators/phase1';
import { registerPhase2Indicators } from '../indicators/phase2';
import { registerPhase3Indicators } from '../indicators/phase3';
import { registerPhase4Indicators } from '../indicators/phase4';

// Core chart class: data management, series API and wiring to renderer
export interface ChartCoreOptions {
  width?: number;
  height?: number;
  locale?: string;
  theme?: 'light' | 'dark';
  renderer?: 'auto' | 'canvas' | 'canvas-worker';
  /** Default visible period in days (e.g., 90 for 3 months). If not set, shows maxVisibleBars. */
  defaultVisibleDays?: number;
  /** Right margin in days for whitespace after latest data (e.g., 14-21 for 2-3 weeks) */
  rightMarginDays?: number;
  /** Enable performance metrics collection (performance.mark/measure). */
  enablePerformanceMetrics?: boolean;
  /** Disable interaction-oriented observers for display-only embeds. */
  interactive?: boolean;
  /** Explicitly control ResizeObserver registration (defaults to interactive). */
  observeResize?: boolean;
  /** Explicitly control IntersectionObserver registration (defaults to interactive). */
  observeVisibility?: boolean;
  /** Optional explicit Worker script URL for canvas-worker mode (npm/bundler friendly). */
  workerUrl?: string | URL;
  /** Optional injected worker instance for manager-level render worker sharing. */
  sharedRenderWorker?: Worker;
  /** Show current renderer mode badge for debugging. */
  debugRendererMode?: boolean;
  /** Indicator line rendering mode for canvas renderer. */
  indicatorLineMode?: 'normal' | 'pseudo-thick';
}

export interface SeriesOptions {
  id?: string;
  type?: 'candlestick' | 'line' | 'bar' | 'area';
  color?: string;
  lineWidth?: number;
  name?: string;
  independentScale?: boolean;
  // Rendering colors (optional)
  outlineColor?: string; // frame and outline (color A)
  wickColor?: string; // wick color (color A)
  upColor?: string; // fill when close >= open (bull) (color B)
  downColor?: string; // fill when close < open (bear) (color C)
}

type SeriesUpdatedPayload = {
  seriesId: string;
  length?: number;
  patch?: { index: number; point: OhlcvPoint }[];
  realtime?: true;
  drained?: number;
};

export interface ChartCoreEventMap {
  seriesAdded: { id: string; options: SeriesOptions };
  seriesUpdated: SeriesUpdatedPayload;
  workerRendererStateChanged: { mode: 'fallback' | 'msg' | 'shared'; label: string };
  rangeChanged: { from: number; to: number };
  realtime: { seriesId: string; point: OhlcvPoint; drained: number };
  realtimeConnected: undefined;
  realtimeDisconnected: undefined;
  prefetchRequested: {
    direction: PrefetchDirection;
    from: number;
    to: number;
    count: number;
    velocityBarsPerMs: number;
  };
  optionsChanged: ChartCoreOptions;
  resize: undefined;
}

interface FeedAdapter {
  subscribe?: (seriesId: string, onPoint: (point: OhlcvPoint) => void) => void;
  unsubscribe?: (seriesId: string) => void;
  prefetch?: (
    seriesId: string,
    request: {
      direction: PrefetchDirection;
      from: number;
      to: number;
      count: number;
      velocityBarsPerMs: number;
    },
  ) => void;
}

import { CanvasRenderer } from '../renderer/canvas/canvasRenderer';
import { WorkerCanvasRenderer } from '../renderer/worker/workerCanvasRenderer';
import type { RenderSnapshot, ViewportRenderer, UnifiedRenderer } from '../renderer/renderer';
import { ColumnarOHLCV } from '../data/columnarStore';
import { FrameAlignedSampler } from '../data/backpressure';
import { DataPrefetcher, type PrefetchDirection } from '../data/prefetcher';
import { TickRingBuffer } from '../data/ringBuffer';

// Minimal ChartCore skeleton to be expanded.
export class ChartCore {
  private static readonly INDICATOR_NULL_SENTINEL_THRESHOLD = -1.0e29;

  private container: HTMLElement;
  private options: ChartCoreOptions;
  private renderer: UnifiedRenderer | null = null;
  private interactionRenderer: ViewportRenderer | null = null;
  private interactionOverlayCanvas: HTMLCanvasElement | null = null;
  private adapter: FeedAdapter | null = null;

  public store: ChartStore;
  private scheduler: RenderScheduler;
  private perfTracker = new PerformanceTracker();
  private batching = false;
  private batchedActions: Action[] = [];
  private currentOverlay: OverlayCommand | null = null;
  private realtimeFlushScheduled = false;
  private realtimeSampler: FrameAlignedSampler<OhlcvPoint> | null = null;
  private prefetcher: DataPrefetcher | null = null;
  private rendererDebugEl: HTMLElement | null = null;
  private lifecycleDisposers: Array<() => void> = [];
  private readonly indicatorComputeStore = new IndicatorComputeStore();
  private readonly indicatorRegistry = new InMemoryIndicatorRegistry();
  private indicatorInstances: IndicatorInstance[] = [];
  private indicatorRecomputeScheduled = false;
  private indicatorRecomputeKey = '';
  private indicatorRecomputeVersion = 0;
  private hudOverlaySnapshotProvider: (() => Readonly<HudOverlaySnapshot>) | null = null;
  private overlayRevisionProvider: (() => number) | null = null;
  private overlayPrimitivesProvider: (() => ReadonlyArray<OverlayRenderPrimitive>) | null = null;

  private workerRendererState: { mode: 'fallback' | 'msg' | 'shared'; label: string } | null = null;

  // internal series store: id -> {options, columnar data (single source of truth — SoA)}
  private seriesStore: Map<string, {
    options: SeriesOptions;
    columnar: ColumnarOHLCV;
    realtimeBuffer: TickRingBuffer | null;
  }> = new Map();

  private getEffectiveRightMarginBars(len?: number, start?: number, visibleCount?: number): number {
    const { rightMargin, startIndex, visibleCount: vc } = this.store.getState().viewport;
    if (rightMargin <= 0) return 0;
    const dataLen = typeof len === 'number' ? len : this.getDataLength();
    const from = typeof start === 'number' ? start : startIndex;
    const visible = typeof visibleCount === 'number' ? visibleCount : vc;
    const maxStartNoMargin = Math.max(0, dataLen - visible);
    const atLatestEdge = from >= maxStartNoMargin - 0.001;
    return atLatestEdge ? rightMargin : 0;
  }

  private isViewportRenderer(renderer: UnifiedRenderer): renderer is ViewportRenderer {
    return typeof (renderer as ViewportRenderer).getLayout === 'function';
  }

  private getViewportRenderer(): ViewportRenderer | null {
    if (this.renderer && this.isViewportRenderer(this.renderer)) return this.renderer;
    return this.interactionRenderer;
  }

  private ensureInteractionRenderer(baseCanvas: HTMLCanvasElement): void {
    if (this.interactionRenderer) return;

    const ownerDocument = this.container.ownerDocument ?? document;
    const overlayCanvas = ownerDocument.createElement('canvas');
    const containerIsCanvas = this.container.tagName.toLowerCase() === 'canvas';

    overlayCanvas.style.width = baseCanvas.style.width || `${baseCanvas.clientWidth || baseCanvas.width}px`;
    overlayCanvas.style.height = baseCanvas.style.height || `${baseCanvas.clientHeight || baseCanvas.height}px`;

    if (!containerIsCanvas) {
      const style = typeof getComputedStyle === 'function' ? getComputedStyle(this.container) : null;
      if (!style || !style.position || style.position === 'static') {
        this.container.style.position = 'relative';
      }
      overlayCanvas.style.position = 'absolute';
      overlayCanvas.style.left = '0';
      overlayCanvas.style.top = '0';
      overlayCanvas.style.width = '100%';
      overlayCanvas.style.height = '100%';
      overlayCanvas.style.pointerEvents = 'none';
      overlayCanvas.style.zIndex = '2';
      this.container.appendChild(overlayCanvas);
      this.interactionOverlayCanvas = overlayCanvas;
    }

    this.interactionRenderer = new CanvasRenderer(containerIsCanvas ? baseCanvas : overlayCanvas);
  }

  private clearInteractionOverlay(): void {
    if (!this.interactionOverlayCanvas || !this.interactionRenderer) return;
    const renderer = this.interactionRenderer;
    const snapshot = this.buildRenderSnapshot();
    if (typeof renderer.clearOverlay === 'function') {
      renderer.clearOverlay(snapshot);
      return;
    }
    const dpr = window.devicePixelRatio || 1;
    const ctx = this.interactionOverlayCanvas.getContext('2d');
    if (!ctx) return;
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.clearRect(0, 0, this.interactionOverlayCanvas.width / dpr, this.interactionOverlayCanvas.height / dpr);
  }

  // simple event emitter
  private listeners: Map<string, Set<(payload?: unknown) => void>> = new Map();

  constructor(container: HTMLElement, options?: ChartCoreOptions) {
    if (!container) throw new Error('Container element required');
    this.container = container;
    this.options = options ?? {};

    this.store = new ChartStore({
      layout: {
        width: (this.options.width ?? container.clientWidth) || 800,
        height: (this.options.height ?? container.clientHeight) || 600,
        dpr: typeof window !== 'undefined' ? (window.devicePixelRatio || 1) : 1
      }
    });

    this.perfTracker.setEnabled(this.options.enablePerformanceMetrics ?? false);

    this.scheduler = new RenderScheduler(
      (actions) => {
        let changed = false;
        for (const action of actions) {
          changed = this.store.dispatch(action) || changed;
        }
        if (changed) {
          this.emitRangeChanged();
        }
        return changed;
      },
      () => this.redraw(),
      this.perfTracker,
    );

    // initialize renderer: prefer an existing canvas inside container
    try {
      const existingCanvas = (this.container.tagName.toLowerCase() === 'canvas')
        ? (this.container as HTMLCanvasElement)
        : this.container.querySelector('canvas');

      const canvas = existingCanvas || this.createCanvas();

      this.renderer = this.createRenderer(canvas);
      this.updateRendererDebugBadge();
    } catch (e) {
      console.warn('Renderer init failed', e);
      try {
        const existingCanvas = (this.container.tagName.toLowerCase() === 'canvas')
          ? (this.container as HTMLCanvasElement)
          : this.container.querySelector('canvas');
        const canvas = existingCanvas || this.createCanvas();

        this.renderer = new CanvasRenderer(canvas);
        this.interactionRenderer = null;
        this.interactionOverlayCanvas = null;
        this.updateRendererDebugBadge();
      } catch {
        this.renderer = null;
        this.interactionRenderer = null;
        this.interactionOverlayCanvas = null;
      }
    }

    registerPhase1Indicators(this.indicatorRegistry);
    registerPhase2Indicators(this.indicatorRegistry);
    registerPhase3Indicators(this.indicatorRegistry);
    registerPhase4Indicators(this.indicatorRegistry);
  }

  setIndicators(instances: IndicatorInstance[]): void {
    this.indicatorInstances = instances.slice();
    this.indicatorRecomputeKey = '';
    this.scheduleIndicatorRecompute();
  }

  getIndicators(): readonly IndicatorInstance[] {
    return this.indicatorInstances;
  }

  setHudOverlaySnapshotProvider(provider: (() => Readonly<HudOverlaySnapshot>) | null): void {
    this.hudOverlaySnapshotProvider = provider;
  }

  setOverlayPrimitiveProviders(
    revisionProvider: (() => number) | null,
    primitivesProvider: (() => ReadonlyArray<OverlayRenderPrimitive>) | null,
  ): void {
    this.overlayRevisionProvider = revisionProvider;
    this.overlayPrimitivesProvider = primitivesProvider;
  }

  private scheduleIndicatorRecompute(): void {
    if (this.indicatorRecomputeScheduled) return;
    this.indicatorRecomputeScheduled = true;
    const version = ++this.indicatorRecomputeVersion;

    queueMicrotask(() => {
      void this.recomputeIndicatorSegments(version);
    });
  }

  private buildIndicatorRecomputeKey(): string {
    const dataVersion = this.store.getState().data.version;
    const primaryLength = this.getPrimaryColumnar()?.length ?? 0;
    const indicatorsKey = this.indicatorInstances
      .map((instance) => `${instance.instanceId}:${instance.id}:${JSON.stringify(instance.params ?? {})}:${instance.enabled !== false ? 1 : 0}`)
      .join('|');
    const gpuKey = 'cpu';
    return `${dataVersion}|${primaryLength}|${gpuKey}|${indicatorsKey}`;
  }

  private async recomputeIndicatorSegments(version: number): Promise<void> {
    this.indicatorRecomputeScheduled = false;
    if (version !== this.indicatorRecomputeVersion) return;

    if (!this.renderer) return;

    const hasIndicators = this.indicatorInstances.length > 0;
    const hasLineSeries = Array.from(this.seriesStore.entries()).some(([id, s]) => s.options.type === 'line' && id !== this.getPrimarySeriesId());
    if (!hasIndicators && !hasLineSeries) return;

    const key = this.buildIndicatorRecomputeKey();
    if (key === this.indicatorRecomputeKey) return;
    this.indicatorRecomputeKey = key;

    const data = this.getPrimaryColumnar();
    if (!data || data.length === 0) return;

    const drawableSeries: Array<{ values: Array<number | null> | Float32Array; color: readonly [number, number, number, number] }> = [];

    for (const instance of this.indicatorInstances) {
      if (instance.enabled === false) continue;
      const definition = this.indicatorRegistry.get(instance.id);
      if (!definition) continue;

      const computed = await this.indicatorComputeStore.computeAsync(
        instance,
        definition as any,
        data as any,
      );
      if (!computed.ok) continue;

      for (const output of definition.outputs) {
        if (output.style !== 'line') continue;
        const values = computed.value[output.name];
        if (!values || values.length === 0) continue;
        drawableSeries.push({
          values,
          color: this.parseColorToRgba(output.color),
        });
      }
    }

    // Include line series from seriesStore (e.g. SMA in demo)
    for (const [id, entry] of this.seriesStore.entries()) {
      if (entry.options.type === 'line' && id !== this.getPrimarySeriesId()) {
        drawableSeries.push({
          values: entry.columnar.close,
          color: this.parseColorToRgba(entry.options.color || '#ffffff'),
        });
      }
    }

    if (version !== this.indicatorRecomputeVersion) return;
    this.redraw();
  }

  private parseColorToRgba(color: string): readonly [number, number, number, number] {
    const fallback: readonly [number, number, number, number] = [0.3059, 0.8039, 0.7686, 1];
    if (!color) return fallback;

    if (color[0] === '#') {
      if (color.length === 7) {
        const r = Number.parseInt(color.slice(1, 3), 16);
        const g = Number.parseInt(color.slice(3, 5), 16);
        const b = Number.parseInt(color.slice(5, 7), 16);
        if (Number.isFinite(r) && Number.isFinite(g) && Number.isFinite(b)) {
          return [r / 255, g / 255, b / 255, 1];
        }
      }
      if (color.length === 4) {
        const r = Number.parseInt(color[1] + color[1], 16);
        const g = Number.parseInt(color[2] + color[2], 16);
        const b = Number.parseInt(color[3] + color[3], 16);
        if (Number.isFinite(r) && Number.isFinite(g) && Number.isFinite(b)) {
          return [r / 255, g / 255, b / 255, 1];
        }
      }
      return fallback;
    }

    const rgbaMatch = color.match(/^rgba?\(([^)]+)\)$/i);
    if (!rgbaMatch) return fallback;
    const parts = rgbaMatch[1].split(',').map((part) => Number(part.trim()));
    if (parts.length < 3) return fallback;

    const r = parts[0];
    const g = parts[1];
    const b = parts[2];
    const a = parts.length >= 4 ? parts[3] : 1;
    if (!Number.isFinite(r) || !Number.isFinite(g) || !Number.isFinite(b) || !Number.isFinite(a)) {
      return fallback;
    }

    const norm = (value: number) => {
      if (value > 1) return Math.max(0, Math.min(1, value / 255));
      return Math.max(0, Math.min(1, value));
    };

    return [norm(r), norm(g), norm(b), Math.max(0, Math.min(1, a))];
  }

  private createRenderer(canvas: HTMLCanvasElement): UnifiedRenderer {
    const backend = this.options.renderer ?? 'auto';

    if (backend === 'canvas-worker') {
      return new WorkerCanvasRenderer(canvas, {
        workerUrl: this.options.workerUrl,
        sharedWorker: this.options.sharedRenderWorker,
        onStateChange: (mode) => {
          const payload = {
            mode,
            label: mode === 'fallback' ? 'canvas (worker-fallback)' : `canvas-worker (${mode})`,
          };
          this.workerRendererState = payload;
          this.emit('workerRendererStateChanged', payload);
        },
      });
    }

    // Fallback: plain canvas (canvas or auto)
    return new CanvasRenderer(canvas);
  }

  private canUseCanvasWorker(canvas: HTMLCanvasElement): boolean {
    if (typeof Worker === 'undefined') return false;
    if (typeof OffscreenCanvas === 'undefined') return false;
    return typeof (canvas as HTMLCanvasElement & { transferControlToOffscreen?: () => OffscreenCanvas }).transferControlToOffscreen === 'function';
  }

  registerLifecycleDisposer(disposer: () => void): void {
    this.lifecycleDisposers.push(disposer);
  }

  onHostResize(width: number, height: number, dpr: number): void {
    this.enqueueAction({
      type: ActionType.RESIZE,
      width: Math.max(1, Math.floor(width)),
      height: Math.max(1, Math.floor(height)),
      dpr,
    });
  }

  onHostVisibilityChange(isVisible: boolean): void {
    if (isVisible) {
      this.scheduler.resume();
      return;
    }
    this.scheduler.pause();
  }

  private getOrCreateRealtimeSampler(): FrameAlignedSampler<OhlcvPoint> {
    if (!this.realtimeSampler) {
      this.realtimeSampler = new FrameAlignedSampler<OhlcvPoint>((seriesId, point) => {
        const entry = this.seriesStore.get(seriesId);
        if (!entry) return;
        this.getOrCreateRealtimeBuffer(entry).push(point);
        this.scheduleRealtimeFlush();
      });
    }
    return this.realtimeSampler;
  }

  private getOrCreatePrefetcher(): DataPrefetcher {
    if (!this.prefetcher) {
      this.prefetcher = new DataPrefetcher((signal) => {
        this.requestPrefetch(signal.direction, signal.bars, signal.velocityBarsPerMs);
      });
    }
    return this.prefetcher;
  }

  private getOrCreateRealtimeBuffer(entry: {
    options: SeriesOptions;
    columnar: ColumnarOHLCV;
    realtimeBuffer: TickRingBuffer | null;
  }): TickRingBuffer {
    if (!entry.realtimeBuffer) {
      entry.realtimeBuffer = new TickRingBuffer();
    }
    return entry.realtimeBuffer;
  }

  private enqueueAction(action: Action): void {
    if (this.batching) {
      this.batchedActions.push(action);
      return;
    }
    this.scheduler.enqueue(action);
  }

  private enqueueActions(actions: Action[]): void {
    if (actions.length === 0) return;
    if (this.batching) {
      // R8: Avoid spread syntax on potentially large arrays
      const len = actions.length;
      for (let i = 0; i < len; i++) {
        this.batchedActions.push(actions[i]);
      }
      return;
    }
    this.scheduler.enqueueBatch(actions);
  }

  batch(work: () => void): void {
    this.batching = true;
    try {
      work();
    } finally {
      this.batching = false;
      if (this.batchedActions.length > 0) {
        this.scheduler.enqueueBatch(this.batchedActions);
        this.batchedActions = [];
      }
    }
  }

  // Event emitter helpers
  on<E extends keyof ChartCoreEventMap>(event: E, cb: (payload: ChartCoreEventMap[E]) => void): void;
  on(event: string, cb: (payload?: unknown) => void): void;
  on(event: string, cb: (payload?: unknown) => void) {
    const set = this.listeners.get(event) ?? new Set();
    set.add(cb);
    this.listeners.set(event, set);
  }

  off<E extends keyof ChartCoreEventMap>(
    event: E,
    cb?: (payload: ChartCoreEventMap[E]) => void,
  ): void;
  off(event: string, cb?: (payload?: unknown) => void): void;
  off(event: string, cb?: (payload?: unknown) => void) {
    if (!this.listeners.has(event)) return;
    if (!cb) { this.listeners.delete(event); return; }
    this.listeners.get(event)!.delete(cb);
  }

  private emit<E extends keyof ChartCoreEventMap>(event: E, payload?: ChartCoreEventMap[E]): void;
  private emit(event: string, payload?: unknown): void;
  private emit(event: string, payload?: unknown) {
    const set = this.listeners.get(event);
    if (!set) return;
    for (const cb of set) cb(payload);
  }

  // Feed adapter contract: adapter should implement subscribe/unsubscribe or similar
  async connectFeed(adapter: FeedAdapter): Promise<void> {
    // basic wiring: adapter.subscribe(seriesId, callback)
    if (!adapter) throw new Error('Adapter required');
    if (typeof adapter.subscribe !== 'function') {
      console.warn('Adapter does not implement subscribe/unsubscribe — storing adapter only');
      // store adapter for future use
      this.adapter = adapter;
      return;
    }
    this.adapter = adapter;
    // subscribe all series if adapter supports it
    for (const seriesId of this.seriesStore.keys()) {
      try {
        adapter.subscribe(seriesId, (point: OhlcvPoint) => this.pushRealtime(seriesId, point));
      } catch (e) {
        console.warn('subscribe failed for', seriesId, e);
      }
    }
    this.emit('realtimeConnected');
  }

  async disconnectFeed(): Promise<void> {
    const adapter = this.adapter;
    if (adapter && typeof adapter.unsubscribe === 'function') {
      for (const seriesId of this.seriesStore.keys()) {
        try { adapter.unsubscribe(seriesId); } catch { };
      }
    }
    this.adapter = null;
    this.emit('realtimeDisconnected');
  }

  async addSeries(options: SeriesOptions): Promise<string> {
    const id = options.id ?? `series_${Math.random().toString(36).slice(2, 9)}`;
    if (this.seriesStore.has(id)) throw new Error(`Series ${id} already exists`);
    this.seriesStore.set(id, {
      options,
      columnar: new ColumnarOHLCV(0),
      realtimeBuffer: null,
    });
    this.emit('seriesAdded', { id, options });
    return id;
  }

  async setSeriesData(seriesId: string, data: OhlcvPoint[] | ColumnarOHLCV, partial = false): Promise<void> {
    const entry = this.seriesStore.get(seriesId);
    if (!entry) throw new Error(`Series ${seriesId} not found`);
    this.perfTracker.measure('upload', () => {
      if (data instanceof ColumnarOHLCV) {
        // Directly adopt columnar storage without copying
        entry.columnar = data as ColumnarOHLCV;
        entry.realtimeBuffer?.clear();
        // Apply default viewport settings on fresh data load
        this.applyDefaultViewport(data);
      } else if (partial) {
        // merge partial at the end (columnar-only path)
        entry.columnar.spliceEnd(data);
        entry.realtimeBuffer?.clear();
      } else {
        entry.columnar.setData(data);
        entry.realtimeBuffer?.clear();
        // Apply default viewport settings on fresh data load
        this.applyDefaultViewport(data);
      }
    });
    this.seriesStore.set(seriesId, entry);

    // Update total bars in store
    this.enqueueAction({ type: ActionType.SET_TOTAL_BARS, count: this.getDataLength() });
    this.scheduleIndicatorRecompute();

    // emit update
    this.emit('seriesUpdated', { seriesId, length: entry.columnar.length });
    // render logic is handled by store subscription if needed
  }

  private applyDefaultViewport(data: OhlcvPoint[] | ColumnarOHLCV): void {
    // Accept either an AoS array or ColumnarOHLCV and avoid allocating via toArray()
    const len = Array.isArray(data) ? data.length : data.length;
    if (len === 0) return;

    const defaultVisibleDays = this.options.defaultVisibleDays;
    const rightMarginDays = this.options.rightMarginDays ?? 0;

    let newVisibleCount: number, newStartIndex: number, newRightMargin: number;

    if (defaultVisibleDays && len >= 2) {
      // Estimate average bar duration from data without allocating
      const firstTime = Array.isArray(data) ? (data[0].time) : (data.time[0]);
      const lastTime = Array.isArray(data) ? (data[len - 1].time) : (data.time[len - 1]);
      const totalMs = lastTime - firstTime;
      const avgBarMs = totalMs / (len - 1);
      const msPerDay = 24 * 60 * 60 * 1000;

      // Calculate visible count based on days
      const visibleBars = Math.ceil((defaultVisibleDays * msPerDay) / avgBarMs);
      const marginBars = Math.ceil((rightMarginDays * msPerDay) / avgBarMs);

      // Set viewport to show last N bars with right margin
      newVisibleCount = Math.min(len, visibleBars);
      newStartIndex = Math.max(0, len - visibleBars);
      newRightMargin = marginBars;
    } else {
      // Default behavior: show last 200 bars
      newVisibleCount = Math.min(200, len);
      newStartIndex = Math.max(0, len - newVisibleCount);
      newRightMargin = 0;
    }

    this.enqueueActions([
      {
        type: ActionType.SET_VIEWPORT,
        startIndex: newStartIndex,
        visibleCount: newVisibleCount,
      },
      {
        type: ActionType.SET_RIGHT_MARGIN,
        rightMargin: newRightMargin,
      },
    ]);
  }

  private getDataLength(): number {
    let max = 0;
    for (const v of this.seriesStore.values()) {
      if (v.columnar.length > max) max = v.columnar.length;
    }
    return max;
  }

  private createCanvas(): HTMLCanvasElement {
    const c = document.createElement('canvas');
    const w = ((this.options.width ?? this.container.clientWidth) || 800) as number;
    const h = ((this.options.height ?? this.container.clientHeight) || 600) as number;
    c.style.width = w + 'px';
    c.style.height = h + 'px';
    this.container.appendChild(c);
    return c;
  }

  private emitRangeChanged(): void {
    const len = this.getDataLength();
    if (len === 0) return;
    const { startIndex, visibleCount } = this.store.getState().viewport;
    const from = Math.max(0, Math.min(len - 1, Math.floor(startIndex)));
    const to = Math.max(0, Math.min(len - 1, from + visibleCount - 1));

    this.emit('rangeChanged', { from, to });
  }

  async updateSeries(seriesId: string, patch: { index: number; point: OhlcvPoint }[]): Promise<void> {
    const entry = this.seriesStore.get(seriesId);
    if (!entry) throw new Error(`Series ${seriesId} not found`);
    for (const p of patch) {
      if (p.index < 0 || p.index >= entry.columnar.length) continue;
      entry.columnar.setAt(p.index, p.point);
    }
    this.emit('seriesUpdated', { seriesId, patch });
    this.enqueueAction({ type: ActionType.SET_TOTAL_BARS, count: this.getDataLength() });
    this.scheduleIndicatorRecompute();
  }

  async pushRealtime(seriesId: string, point: OhlcvPoint): Promise<void> {
    if (!this.seriesStore.has(seriesId)) throw new Error(`Series ${seriesId} not found`);
    this.getOrCreateRealtimeSampler().push(seriesId, point);
  }

  private scheduleRealtimeFlush(): void {
    if (this.realtimeFlushScheduled) return;
    this.realtimeFlushScheduled = true;
    queueMicrotask(() => {
      this.realtimeFlushScheduled = false;
      this.flushRealtimeBuffers();
    });
  }

  private flushRealtimeBuffers(): void {
    let hasAnyRealtime = false;

    for (const [seriesId, entry] of this.seriesStore.entries()) {
      const realtimeBuffer = entry.realtimeBuffer;
      if (!realtimeBuffer || realtimeBuffer.size() === 0) continue;

      hasAnyRealtime = true;
      const drained = realtimeBuffer.drainTo(entry.columnar);

      if (drained > 0) {
        // Mirror realtime updates to WASM engine (only for non-WasmBacked columnar)
        const lastPoint = entry.columnar.getLastPoint();
        if (lastPoint) {
          this.emit('realtime', { seriesId, point: lastPoint, drained });
          this.emit('seriesUpdated', { seriesId, realtime: true, drained });
        }
      }
    }

    if (hasAnyRealtime) {
      this.enqueueAction({ type: ActionType.SET_TOTAL_BARS, count: this.getDataLength() });
      this.scheduleIndicatorRecompute();
    }
  }

  getVisibleRange(): { from: number; to: number; rightMarginBars?: number } | null {
    const len = this.getDataLength();
    if (len === 0) return null;
    const { startIndex, visibleCount } = this.store.getState().viewport;
    const from = Math.max(0, Math.min(len - 1, Math.floor(startIndex)));
    const to = Math.max(0, Math.min(len - 1, from + visibleCount - 1));
    return { from, to, rightMarginBars: this.getEffectiveRightMarginBars(len, from, visibleCount) };
  }

  setVisibleRange(from: number, to: number): void {
    // programmatic pan/zoom by indices
    const len = this.getDataLength();
    if (len === 0) return;
    const f = Math.max(0, Math.min(len - 1, from));
    const t = Math.max(0, Math.min(len - 1, to));

    this.enqueueAction({
      type: ActionType.SET_VIEWPORT,
      startIndex: f,
      visibleCount: Math.max(1, t - f + 1)
    });
  }

  setViewport(fromIndex: number, toIndex: number): void {
    this.setVisibleRange(fromIndex, toIndex);
  }

  panBy(deltaIndex: number): void {
    this.panByBars(deltaIndex);
  }

  panByBars(deltaBars: number): void {
    this.enqueueAction({ type: ActionType.PAN, deltaBars });
    this.getOrCreatePrefetcher().recordPan(deltaBars);
  }

  private requestPrefetch(direction: PrefetchDirection, bars: number, velocityBarsPerMs: number): void {
    const visible = this.getVisibleRange();
    if (!visible) return;

    const request = direction === 'right'
      ? {
        direction,
        from: visible.to + 1,
        to: visible.to + bars,
        count: bars,
        velocityBarsPerMs,
      }
      : {
        direction,
        from: Math.max(0, visible.from - bars),
        to: Math.max(0, visible.from - 1),
        count: bars,
        velocityBarsPerMs,
      };

    this.emit('prefetchRequested', request);

    if (!this.adapter || typeof this.adapter.prefetch !== 'function') return;
    for (const seriesId of this.seriesStore.keys()) {
      try {
        this.adapter.prefetch(seriesId, request);
      } catch (error) {
        console.warn('prefetch failed for', seriesId, error);
      }
    }
  }

  zoomAt(factor: number, centerIndex?: number, centerRatio?: number): void {
    const len = this.getDataLength();
    if (len === 0) return;

    let centerX = 0.5;
    if (typeof centerRatio === 'number') {
      centerX = centerRatio;
    } else if (typeof centerIndex === 'number') {
      const { startIndex, visibleCount } = this.store.getState().viewport;
      centerX = (centerIndex - startIndex) / visibleCount;
    }

    this.enqueueAction({ type: ActionType.ZOOM, factor, centerX });
  }

  applyOptions(options: ChartCoreOptions): void {
    Object.assign(this.options, options);
    if (options.width || options.height) {
      this.enqueueAction({
        type: ActionType.RESIZE,
        width: options.width ?? this.store.getState().layout.width,
        height: options.height ?? this.store.getState().layout.height,
        dpr: this.store.getState().layout.dpr
      });
    }
    this.updateRendererDebugBadge();
    this.emit('optionsChanged', this.options);
  }

  private getRendererModeLabel(): string {
    const renderer = this.renderer;
    if (!renderer) return 'none';
    if (renderer instanceof WorkerCanvasRenderer) {
      return renderer.getDebugModeLabel();
    }
    if (renderer instanceof CanvasRenderer) {
      return 'canvas';
    }
    return 'unknown';
  }

  private updateRendererDebugBadge(): void {
    if (!this.options.debugRendererMode) {
      if (this.rendererDebugEl?.parentElement) {
        this.rendererDebugEl.parentElement.removeChild(this.rendererDebugEl);
      }
      this.rendererDebugEl = null;
      return;
    }

    let mode = this.getRendererModeLabel();
    if (!this.rendererDebugEl) {
      const el = document.createElement('div');
      el.style.position = 'absolute';
      el.style.right = '8px';
      el.style.top = '8px';
      el.style.zIndex = '1200';
      el.style.pointerEvents = 'none';
      el.style.font = '11px monospace';
      el.style.padding = '4px 6px';
      el.style.borderRadius = '4px';
      el.style.background = 'rgba(0,0,0,0.72)';
      el.style.color = '#fff';

      if (this.container.ownerDocument?.defaultView?.getComputedStyle(this.container).position === 'static') {
        this.container.style.position = 'relative';
      }
      this.container.appendChild(el);
      this.rendererDebugEl = el;
    }

    this.rendererDebugEl.textContent = `renderer: ${mode}`;
  }

  getRawStartIndex(): number {
    return this.store.getState().viewport.startIndex;
  }

  getRendererMode(): string {
    return this.getRendererModeLabel();
  }

  getWorkerRendererState(): { mode: 'fallback' | 'msg' | 'shared'; label: string } | null {
    return this.workerRendererState;
  }

  getPrimarySeriesId(): string | null {
    const first = this.seriesStore.keys().next();
    return first.done ? null : first.value;
  }

  /** Primary シリーズの ColumnarOHLCV を取得 (WASM かどうかを問わず) */
  getPrimaryColumnar(): ColumnarOHLCV | null {
    const id = this.getPrimarySeriesId();
    if (!id) return null;
    return this.seriesStore.get(id)?.columnar ?? null;
  }

  getPrimaryData(): readonly OhlcvPoint[] {
    const id = this.getPrimarySeriesId();
    if (!id) return [];
    const entry = this.seriesStore.get(id);
    // Legacy support: Try to avoid full allocation if possible,
    // but this API contract demands an array of objects.
    // TODO(R8): Deprecate this method in favor of getPrimaryColumnar()
    return entry?.columnar.toArray() ?? [];
  }


  getPrimarySeriesOptions(): SeriesOptions | null {
    const id = this.getPrimarySeriesId();
    if (!id) return null;
    const entry = this.seriesStore.get(id);
    return entry?.options ?? null;
  }

  getSeriesEntry(seriesId: string): { options: SeriesOptions; data: readonly OhlcvPoint[] } | null {
    const entry = this.seriesStore.get(seriesId);
    if (!entry) return null;
    return { options: entry.options, data: entry.columnar.toArray() };
  }

  getSeriesColumnar(seriesId: string): ColumnarOHLCV | null {
    const entry = this.seriesStore.get(seriesId);
    return entry?.columnar ?? null;
  }

  getLayout(options?: RendererViewportOptions): RendererLayout | null {
    const renderer = this.getViewportRenderer();
    if (!renderer) return null;
    const data = this.getPrimaryColumnar();
    if (!data) return null;
    const { startIndex, visibleCount } = this.store.getState().viewport;
    const effectiveRightMargin = this.getEffectiveRightMarginBars();

    return renderer.getLayout(data, {
      startIndex,
      visibleCount,
      rightMarginBars: effectiveRightMargin,
      ...options
    });
  }

  mapClientToData(clientX: number, clientY: number, options?: RendererViewportOptions): MapClientToDataResult | null {
    return this.hitTest(clientX, clientY, options);
  }

  hitTest(clientX: number, clientY: number, options?: RendererViewportOptions): MapClientToDataResult | null {
    const renderer = this.getViewportRenderer();
    if (!renderer) return null;
    const data = this.getPrimaryColumnar();
    if (!data) return null;
    const { startIndex, visibleCount } = this.store.getState().viewport;
    const effectiveRightMargin = this.getEffectiveRightMarginBars();

    return renderer.hitTest(clientX, clientY, data, {
      startIndex,
      visibleCount,
      rightMarginBars: effectiveRightMargin,
      ...options
    });
  }

  drawCrosshair(clientX: number, clientY: number, options?: RendererViewportOptions): void {
    this.setCrosshairOverlay(clientX, clientY, options);
  }

  setCrosshairOverlay(clientX: number, clientY: number, options?: RendererViewportOptions): void {
    const renderer = this.getViewportRenderer();
    if (!renderer) return;
    this.currentOverlay = {
      type: 'crosshair',
      clientX,
      clientY,
      options,
    };

    if (renderer === this.interactionRenderer) {
      renderer.resize();
      this.clearInteractionOverlay();
    }

    const snapshot = this.buildRenderSnapshot();
    if (typeof renderer.renderOverlay === 'function') {
      renderer.renderOverlay(snapshot, this.currentOverlay);
      return;
    }

    if (typeof renderer.drawCrosshairAt !== 'function') return;
    const data = this.getPrimaryColumnar();
    if (!data) return;
    const { startIndex, visibleCount } = this.store.getState().viewport;
    const effectiveRightMargin = this.getEffectiveRightMarginBars();

    renderer.drawCrosshairAt(clientX, clientY, data, {
      startIndex,
      visibleCount,
      rightMarginBars: effectiveRightMargin,
      ...options
    });
  }

  clearOverlay(): void {
    this.currentOverlay = null;
    const renderer = this.getViewportRenderer();
    if (!renderer) return;
    if (renderer === this.interactionRenderer) {
      this.clearInteractionOverlay();
      return;
    }
    const snapshot = this.buildRenderSnapshot();
    if (typeof renderer.clearOverlay === 'function') {
      renderer.clearOverlay(snapshot);
      return;
    }
    this.redraw();
  }

  private buildRenderSnapshot(): RenderSnapshot {
    const effectiveRightMarginBars = this.getEffectiveRightMarginBars();
    const { startIndex, visibleCount } = this.store.getState().viewport;
    const { width, height, dpr } = this.store.getState().layout;
    const startFloor = Math.floor(Math.max(0, startIndex));
    const series: Array<RenderSnapshot['series'][number]> = [];

    for (const [id, entry] of this.seriesStore.entries()) {
      series.push({
        id,
        // R8: Zero-Copy Enforcement
        // Pass empty array for 'data' to ensure renderers use 'visibleSlice'.
        // Legacy renderers depending on 'data' will need migration.
        data: [],
        visibleSlice: entry.columnar.sliceView(startFloor, visibleCount + 1),
        options: entry.options,
      });
    }

    return {
      viewport: {
        startIndex,
        visibleCount,
        rightMarginBars: effectiveRightMarginBars,
      },
      layout: {
        width,
        height,
        dpr,
      },
      hudOverlay: this.hudOverlaySnapshotProvider ? this.hudOverlaySnapshotProvider() : undefined,
      overlayRevision: this.overlayRevisionProvider ? this.overlayRevisionProvider() : 0,
      overlayPrimitives: this.overlayPrimitivesProvider ? this.overlayPrimitivesProvider() : undefined,
      primarySeriesId: this.getPrimarySeriesId(),
      series,
    };
  }

  redraw(): void {
    this.perfTracker.measure('draw', () => {
      const renderer = this.renderer;
      if (!renderer) return;

      this.scheduleIndicatorRecompute();

      const snapshot = this.buildRenderSnapshot();
      renderer.render(snapshot);

      if (this.isViewportRenderer(renderer) && typeof renderer.drawSeries === 'function') {
        const { startIndex, visibleCount } = snapshot.viewport;
        const effectiveRightMarginBars = snapshot.viewport.rightMarginBars;
        const primarySeriesId = this.getPrimarySeriesId();
        const primaryColumnar = primarySeriesId ? this.getSeriesColumnar(primarySeriesId) : null;
        const sharedLayout = primaryColumnar
          ? renderer.getLayout(primaryColumnar, {
            startIndex,
            visibleCount,
            rightMarginBars: effectiveRightMarginBars,
          })
          : null;
        for (const [seriesId, entry] of this.seriesStore.entries()) {
          const isPrimarySeries = seriesId === primarySeriesId;
          const useSharedScale = entry.options.independentScale !== true;
          try {
            renderer.drawSeries(seriesId, entry.columnar, {
              ...entry.options,
              startIndex,
              visibleCount,
              rightMarginBars: effectiveRightMarginBars,
              background: isPrimarySeries ? undefined : 'rgba(0,0,0,0)',
              yMinOverride: useSharedScale ? sharedLayout?.yMin : undefined,
              yMaxOverride: useSharedScale ? sharedLayout?.yMax : undefined,
            });
          } catch (e) {
            console.warn(e);
          }
        }
      }

      // Re-apply active overlay after base render
      const viewportRenderer = this.getViewportRenderer();
      if (!viewportRenderer) return;

      if (this.currentOverlay) {
        if (viewportRenderer === this.interactionRenderer) {
          // If we are in hybrid mode (WebGPU/WebGL), the interaction renderer
          // was already resized/cleared and axes were drawn in the block above.
          // Calling resize() again here would wipe the axes.
          if (this.isViewportRenderer(renderer)) {
            viewportRenderer.resize();
          }
          const data = this.getPrimaryColumnar();
          if (!data) return;
          const { startIndex, visibleCount } = snapshot.viewport;
          viewportRenderer.drawCrosshairAt(
            this.currentOverlay.clientX,
            this.currentOverlay.clientY,
            data,
            {
              startIndex,
              visibleCount,
              rightMarginBars: snapshot.viewport.rightMarginBars,
              ...(this.currentOverlay.options ?? {}),
            },
          );
        } else if (typeof viewportRenderer.renderOverlay === 'function') {
          viewportRenderer.renderOverlay(snapshot, this.currentOverlay);
        }
      } else if (viewportRenderer === this.interactionRenderer) {
        // If we are using the interaction renderer as the viewport renderer (WebGPU/WebGL mode),
        // we must NOT clear it here if it's also responsible for drawing the axes (which we just drew above).
        // The axes/grid are part of the 'base' layer in this mode, not a transient overlay.
        // We only need to clear if we had a crosshair previously that needs removal,
        // but CanvasRenderer.clearOverlay() restores from a base layer that might not exist or be stale.

        // Since we already cleared the interaction renderer at the start of the interaction block above
        // (via overlayRenderer.clear()), we don't need to do anything here if there's no overlay.
        // The axes drawn above should remain visible.
      } else if (typeof viewportRenderer.clearOverlay === 'function') {
        viewportRenderer.clearOverlay(snapshot);
      }
    });
  }

  getPerformanceSnapshot(): PerfSnapshot {
    return this.perfTracker.getSnapshot();
  }

  resetPerformanceMetrics(): void {
    this.perfTracker.reset();
  }

  setPerformanceMetricsEnabled(enabled: boolean): void {
    this.perfTracker.setEnabled(enabled);
  }

  flush(): void {
    this.scheduler.flushSync();
  }

  resize(): void {
    this.interactionRenderer?.resize();
    // handle container resize
    this.enqueueAction({
      type: ActionType.RESIZE,
      width: this.container.clientWidth,
      height: this.container.clientHeight,
      dpr: window.devicePixelRatio || 1
    });
    this.emit('resize');
  }

  async destroy(): Promise<void> {
    // cleanup
    for (const dispose of this.lifecycleDisposers) {
      try {
        dispose();
      } catch {
        // no-op
      }
    }
    this.lifecycleDisposers = [];
    this.scheduler.destroy();
    this.realtimeSampler?.destroy();
    this.prefetcher?.reset();
    await this.disconnectFeed();
    this.seriesStore.clear();
    this.listeners.clear();
    if (this.rendererDebugEl?.parentElement) {
      this.rendererDebugEl.parentElement.removeChild(this.rendererDebugEl);
    }
    this.rendererDebugEl = null;
    this.indicatorComputeStore.reset();
    this.indicatorInstances = [];
    this.indicatorRecomputeKey = '';
    this.renderer?.destroy?.();
    this.interactionRenderer?.destroy?.();
    if (this.interactionOverlayCanvas?.parentElement) {
      this.interactionOverlayCanvas.parentElement.removeChild(this.interactionOverlayCanvas);
    }
    this.interactionOverlayCanvas = null;
    this.interactionRenderer = null;
    this.adapter = null;
    this.renderer = null;
  }
}

