// src/core/store/assertNever.ts

/**
 * Exhaustive check helper for discriminated unions.
 * Place in the `default` branch of a switch to get a compile-time error
 * when a new variant is added to the union but not handled.
 */
export function assertNever(x: never): never {
  throw new Error(`Unexpected action: ${(x as { type: string }).type}`);
}
