type WasmAssetKind = 'legacy' | 'new';

type WasmAssetVariant = 'default' | 'shared-preferred';

type AssetOverrideHost = typeof globalThis & {
  __MOCHART_ASSET_BASE_URL__?: string;
};

const WASM_FILE_NAMES: Record<WasmAssetKind, string> = {
  legacy: 'mochart_wasm_bg.wasm',
  new: 'mochart_wasm_new_bg.wasm',
};

const WASM_PATH_CANDIDATES: ReadonlyArray<string> = [
  './pkg/',
  '../pkg/',
  '/src/pkg/',
  '/dist/pkg/',
];

const SHARED_WASM_PATH_CANDIDATES: ReadonlyArray<string> = [
  './pkg-shared/',
  '../pkg-shared/',
  '/src/pkg-shared/',
  '/dist/pkg-shared/',
];

function resolveOverrideBaseUrl(): string | null {
  const host = globalThis as AssetOverrideHost;
  const override = host.__MOCHART_ASSET_BASE_URL__;
  if (typeof override !== 'string') return null;
  const trimmed = override.trim();
  if (trimmed.length === 0) return null;
  return trimmed.endsWith('/') ? trimmed : `${trimmed}/`;
}

function buildCandidateUrls(kind: WasmAssetKind, variant: WasmAssetVariant): URL[] {
  const fileName = WASM_FILE_NAMES[kind];
  const urls: URL[] = [];
  const overrideBase = resolveOverrideBaseUrl();

  if (overrideBase) {
    urls.push(new URL(fileName, overrideBase));
  }

  const pathCandidates = variant === 'shared-preferred'
    ? [...SHARED_WASM_PATH_CANDIDATES, ...WASM_PATH_CANDIDATES]
    : WASM_PATH_CANDIDATES;

  for (let index = 0; index < pathCandidates.length; index++) {
    urls.push(new URL(`${pathCandidates[index]}${fileName}`, import.meta.url));
  }

  return urls;
}

export async function fetchMochartWasmBytes(kind: WasmAssetKind, variant: WasmAssetVariant = 'default'): Promise<ArrayBuffer> {
  const urls = buildCandidateUrls(kind, variant);
  let lastError: unknown = null;

  for (let index = 0; index < urls.length; index++) {
    const url = urls[index];
    try {
      const response = await fetch(url);
      if (!response.ok) {
        lastError = new Error(`HTTP ${response.status} for ${url.href}`);
        continue;
      }
      return await response.arrayBuffer();
    } catch (error) {
      lastError = error;
    }
  }

  throw lastError instanceof Error
    ? lastError
    : new Error(`Failed to resolve Mochart WASM asset for ${kind}`);
}