import type { ColumnarOHLCV } from './columnarStore';

export interface TickPoint {
  time: number;
  open: number;
  high: number;
  low: number;
  close: number;
  volume: number;
}

/**
 * Fixed-capacity SoA ring buffer for realtime tick ingestion.
 *
 * Internal storage uses 6 TypedArrays (contiguous memory, GC-invisible)
 * instead of an Object[] to ensure spatial locality and zero GC pressure
 * on the push() hot path. drain() reconstructs TickPoint objects on the
 * cold path (once per frame) which is acceptable.
 */
export class TickRingBuffer {
  private readonly _capacity: number;
  private readonly _time: Float64Array;
  private readonly _open: Float32Array;
  private readonly _high: Float32Array;
  private readonly _low: Float32Array;
  private readonly _close: Float32Array;
  private readonly _volume: Float32Array;
  private _head = 0;
  private _tail = 0;
  private _count = 0;

  constructor(capacity = 2048) {
    this._capacity = Math.max(1, capacity | 0);
    this._time = new Float64Array(this._capacity);
    this._open = new Float32Array(this._capacity);
    this._high = new Float32Array(this._capacity);
    this._low = new Float32Array(this._capacity);
    this._close = new Float32Array(this._capacity);
    this._volume = new Float32Array(this._capacity);
  }

  size(): number {
    return this._count;
  }

  clear(): void {
    this._head = 0;
    this._tail = 0;
    this._count = 0;
  }

  push(point: TickPoint): void {
    const i = this._head;
    this._time[i] = point.time;
    this._open[i] = point.open;
    this._high[i] = point.high;
    this._low[i] = point.low;
    this._close[i] = point.close;
    this._volume[i] = point.volume;
    this._head = (i + 1) % this._capacity;

    if (this._count === this._capacity) {
      this._tail = (this._tail + 1) % this._capacity;
      return;
    }

    this._count++;
  }

  drainTo(target: ColumnarOHLCV): number {
    let drained = 0;
    while (this._count > 0) {
      const i = this._tail;
      // Use appendOrUpdateLastRaw to handle intra-bar updates correctly
      target.appendOrUpdateLastRaw(
        this._time[i],
        this._open[i],
        this._high[i],
        this._low[i],
        this._close[i],
        this._volume[i]
      );
      this._tail = (i + 1) % this._capacity;
      this._count--;
      drained++;
    }
    return drained;
  }

  drain(consumer: (point: TickPoint) => void): number {
    let drained = 0;
    while (this._count > 0) {
      const i = this._tail;
      consumer({
        time: this._time[i],
        open: this._open[i],
        high: this._high[i],
        low: this._low[i],
        close: this._close[i],
        volume: this._volume[i],
      });
      this._tail = (i + 1) % this._capacity;
      this._count--;
      drained++;
    }
    return drained;
  }
}