import type { Action } from './store/actions';
import { ActionType } from './store/actions';

const KEEP_LAST_TYPES = new Set<Action['type']>([
  ActionType.ZOOM,
  ActionType.SET_VIEWPORT,
  ActionType.SET_RIGHT_MARGIN,
  ActionType.RESIZE,
  ActionType.SET_TOTAL_BARS,
  ActionType.DRAG,
  ActionType.PINCH,
  ActionType.HOVER,
]);

/**
 * Coalesce actions raised in the same frame.
 * - PAN: summed into one action
 * - keep-last actions: only latest action is kept
 * - others: preserved in order
 */
export function coalesce(actions: Action[]): Action[] {
  if (actions.length <= 1) return actions;

  const result: Action[] = [];
  let panIndex: number | null = null;
  const latestIndices = new Map<Action['type'], number>();

  for (const action of actions) {
    if (action.type === ActionType.PAN) {
      if (panIndex === null) {
        panIndex = result.length;
        result.push(action);
      } else {
        const current = result[panIndex];
        if (current.type === ActionType.PAN) {
          result[panIndex] = { type: ActionType.PAN, deltaBars: current.deltaBars + action.deltaBars };
        }
      }
      continue;
    }

    if (KEEP_LAST_TYPES.has(action.type)) {
      const existing = latestIndices.get(action.type);
      if (existing === undefined) {
        latestIndices.set(action.type, result.length);
        result.push(action);
      } else {
        result[existing] = action;
      }
      continue;
    }

    result.push(action);
  }

  return result;
}
