// src/core/store/store.ts
import { ChartState, REQUIRED_INITIAL_STATE } from './types';
import { Action } from './actions';
import { chartReducer } from './reducer';

type Listener = (state: ChartState) => void;
type Selector<T> = (state: ChartState) => T;
type DispatchMiddleware = (payload: {
  action: Action;
  prevState: ChartState;
  nextState: ChartState;
  changed: boolean;
}) => void;

export class ChartStore {
  private state: ChartState;
  private listeners: Set<Listener> = new Set();
  private middlewares: Set<DispatchMiddleware> = new Set();
  
  constructor(initialState: Partial<ChartState> = {}) {
    this.state = {
      ...REQUIRED_INITIAL_STATE,
      ...initialState,
      // Deep merge logic might be needed for nested objects if partial state provided
      // For now, assume top level keys or full nested object replacement
      // OR specifically merge nested viewport if provided
      viewport: {
        ...REQUIRED_INITIAL_STATE.viewport,
        ...(initialState.viewport || {}),
      },
      layout: {
        ...REQUIRED_INITIAL_STATE.layout,
        ...(initialState.layout || {}),
      },
    };
  }

  /**
   * Get the current state.
   */
  getState(): ChartState {
    return this.state;
  }

  /**
   * Dispatch an action to update the state.
   * Currently synchronous. R2 will introduce scheduling for rendering.
   */
  dispatch(action: Action): boolean {
    const previousState = this.state;
    this.state = chartReducer(previousState, action);
    const changed = this.state !== previousState;

    if (changed) {
      this.notify();
    }

    if (this.middlewares.size > 0) {
      const payload = {
        action,
        prevState: previousState,
        nextState: this.state,
        changed,
      };
      for (const middleware of this.middlewares) {
        middleware(payload);
      }
    }

    return changed;
  }

  use(middleware: DispatchMiddleware): () => void {
    this.middlewares.add(middleware);
    return () => {
      this.middlewares.delete(middleware);
    };
  }

  /**
   * Subscribe to state changes.
   * Returns an unsubscribe function.
   */
  subscribe(listener: Listener): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }

  /**
   * Select a part of the state.
   * (Helper for potential future React integration or memoization)
   */
  select<T>(selector: Selector<T>): T {
    return selector(this.state);
  }

  private notify() {
    this.listeners.forEach(listener => listener(this.state));
  }
  
  /**
   * Reset store to initial state (useful for tests or re-init)
   */
  reset() {
      this.state = REQUIRED_INITIAL_STATE;
      this.notify();
  }
}
