import type { IndicatorDefinition, IndicatorResult, MultiSeriesOutput } from '../indicatorTypes';
import type { IndicatorInstance, OhlcvPoint } from '../types';
import { ColumnarOHLCV } from '../../data/columnarStore';

const GPU_NULL_SENTINEL_THRESHOLD = -1.0e29;

type IndicatorRuntimeCache = {
  indicatorId: string;
  paramsKey: string;
  dataLength: number;
  lastTime: number;
  values: MultiSeriesOutput;
  state: unknown;
};

export type IndicatorComputeStats = Readonly<{
  cacheEntries: number;
}>;

export class IndicatorComputeStore {
  private readonly indicatorRuntimeCache = new Map<string, IndicatorRuntimeCache>();

  getStats(): IndicatorComputeStats {
    return {
      cacheEntries: this.indicatorRuntimeCache.size,
    };
  }

  reset(): void {
    this.indicatorRuntimeCache.clear();
  }

  compute(
    instance: IndicatorInstance,
    def: IndicatorDefinition<any, OhlcvPoint>,
    data: OhlcvPoint[] | ColumnarOHLCV,
  ): IndicatorResult<MultiSeriesOutput> {
    const prepared = this.prepareCompute(instance, def, data);
    const cached = this.tryReadCache(prepared as any);
    if (cached) return cached;

    const incremental = this.tryIncremental(prepared as any);
    if (incremental) return incremental;

    return this.computeAndCache(prepared as any);
  }

  async computeAsync(
    instance: IndicatorInstance,
    def: IndicatorDefinition<any, OhlcvPoint>,
    data: OhlcvPoint[] | ColumnarOHLCV,
  ): Promise<IndicatorResult<MultiSeriesOutput>> {
    const prepared = this.prepareCompute(instance, def, data);
    const cached = this.tryReadCache(prepared as any);
    if (cached) return cached;

    const incremental = this.tryIncremental(prepared as any);
    if (incremental) return incremental;

    return this.computeAndCache(prepared as any);
  }

  private prepareCompute(
    instance: IndicatorInstance,
    def: IndicatorDefinition<any, OhlcvPoint>,
    data: OhlcvPoint[] | ColumnarOHLCV,
  ): {
    instance: IndicatorInstance;
    def: IndicatorDefinition<any, OhlcvPoint>;
    data: OhlcvPoint[] | ColumnarOHLCV;
    params: Record<string, unknown>;
    paramsKey: string;
    dataLength: number;
    lastTime: number;
    cache: IndicatorRuntimeCache | undefined;
  } {
    const params: Record<string, unknown> = instance.params ?? {};
    const paramsKey = JSON.stringify(params);
    const dataLength = data.length;
    let lastTime = -1;
    if (dataLength > 0) {
      if (data instanceof Array) {
        lastTime = data[dataLength - 1].time;
      } else {
        lastTime = data.time[dataLength - 1];
      }
    }
    const cache = this.indicatorRuntimeCache.get(instance.instanceId);

    return {
      instance,
      def,
      data,
      params,
      paramsKey,
      dataLength,
      lastTime,
      cache,
    };
  }

  private tryReadCache(prepared: {
    def: IndicatorDefinition<any, OhlcvPoint>;
    paramsKey: string;
    dataLength: number;
    lastTime: number;
    cache: IndicatorRuntimeCache | undefined;
  }): IndicatorResult<MultiSeriesOutput> | null {
    const { def, paramsKey, dataLength, lastTime, cache } = prepared;

    if (
      cache &&
      cache.indicatorId === def.id &&
      cache.paramsKey === paramsKey &&
      cache.dataLength === dataLength &&
      cache.lastTime === lastTime
    ) {
      return { ok: true, value: cache.values };
    }

    return null;
  }

  private tryIncremental(prepared: {
    instance: IndicatorInstance;
    def: IndicatorDefinition<any, OhlcvPoint>;
    data: OhlcvPoint[] | ColumnarOHLCV;
    params: Record<string, unknown>;
    paramsKey: string;
    dataLength: number;
    lastTime: number;
    cache: IndicatorRuntimeCache | undefined;
  }): IndicatorResult<MultiSeriesOutput> | null {
    const { instance, def, data, params, paramsKey, dataLength, lastTime, cache } = prepared;

    if (
      def.update &&
      cache &&
      cache.indicatorId === def.id &&
      cache.paramsKey === paramsKey &&
      cache.dataLength + 1 === dataLength &&
      dataLength > 0
    ) {
      const nextBar = (data instanceof Array) ? data[dataLength - 1] : data.getAt(dataLength - 1);
      if (!nextBar) return null;
      const incremental = def.update(cache.state, nextBar, params);
      if (incremental.ok) {
        const nextValues: MultiSeriesOutput = {};
        for (const output of def.outputs) {
          const prevSeries = cache.values[output.name] ?? [];
          const nextValue = incremental.value.values[output.name] ?? null;
          nextValues[output.name] = [...prevSeries, nextValue];
        }
        this.indicatorRuntimeCache.set(instance.instanceId, {
          indicatorId: def.id,
          paramsKey,
          dataLength,
          lastTime,
          values: nextValues,
          state: incremental.value.state,
        });
        return { ok: true, value: nextValues };
      }
    }

    return null;
  }

  private computeAndCache(prepared: {
    instance: IndicatorInstance;
    def: IndicatorDefinition<any, OhlcvPoint>;
    data: OhlcvPoint[] | ColumnarOHLCV;
    params: Record<string, unknown>;
    paramsKey: string;
    dataLength: number;
    lastTime: number;
  }): IndicatorResult<MultiSeriesOutput> {
    const { instance, def, data, params, paramsKey, dataLength, lastTime } = prepared;

    const full = def.calculate((data as any), params);
    if (!full.ok) return full;

    this.indicatorRuntimeCache.set(instance.instanceId, {
      indicatorId: def.id,
      paramsKey,
      dataLength,
      lastTime,
      values: full.value,
      state: this.deriveIncrementalState(def, full.value, params, data),
    });

    return full;
  }

  private clampNumberParam(raw: unknown, fallback: number, min: number, max: number): number {
    const value = typeof raw === 'number' ? raw : Number(raw);
    if (!Number.isFinite(value)) return fallback;
    return Math.max(min, Math.min(max, value));
  }

  private extractCloseValues(data: OhlcvPoint[] | ColumnarOHLCV): Float32Array {
    if ('close' in data) {
      // ColumnarOHLCV or similar
      return data.close;
    }
    const out = new Float32Array(data.length);
    for (let i = 0; i < data.length; i++) {
      out[i] = data[i].close;
    }
    return out;
  }

  private floatSeriesToIndicatorValues(source: Float32Array): Array<number | null> {
    const out = new Array<number | null>(source.length);
    for (let i = 0; i < source.length; i++) {
      const v = source[i];
      out[i] = Number.isFinite(v) && v > GPU_NULL_SENTINEL_THRESHOLD ? v : null;
    }
    return out;
  }

  private deriveIncrementalState(
    def: IndicatorDefinition<any, OhlcvPoint>,
    values: MultiSeriesOutput,
    params: Record<string, unknown>,
    data: OhlcvPoint[] | ColumnarOHLCV,
  ): unknown {
    if (def.id === 'sma') {
      const period = Number(params.period ?? 20);
      const safePeriod = Math.max(2, Number.isFinite(period) ? period : 20);
      const start = Math.max(0, data.length - safePeriod);
      const windowLength = data.length - start;
      const window = new Array<number>(windowLength);
      let sum = 0;
      if (data instanceof Array) {
        for (let i = 0; i < windowLength; i++) {
          const close = data[start + i].close;
          window[i] = close;
          sum += close;
        }
      } else {
        const closeArr = data.close;
        for (let i = 0; i < windowLength; i++) {
          const close = closeArr[start + i];
          window[i] = close;
          sum += close;
        }
      }
      return { window, sum };
    }

    if (def.id === 'ema') {
      const emaSeries = values.ema;
      const fallback = data.length > 0
        ? ((data instanceof Array) ? data[data.length - 1].close : data.close[data.length - 1])
        : 0;
      let lastNonNull: number | null = null;
      if (emaSeries) {
        for (let i = emaSeries.length - 1; i >= 0; i--) {
          const value = emaSeries[i];
          if (value != null) {
            lastNonNull = value;
            break;
          }
        }
      }
      return {
        last: typeof lastNonNull === 'number' ? lastNonNull : fallback,
        index: Math.max(0, data.length - 1),
      };
    }

    return null;
  }
}