// src/core/store/reducer.ts
import { ChartState } from './types';
import { Action, ActionType } from './actions';
import { assertNever } from './assertNever';

const MIN_VISIBLE_BARS = 5;

/**
 * Pure reducer function for ChartState.
 */
export function chartReducer(state: ChartState, action: Action): ChartState {
  switch (action.type) {
    case ActionType.PAN: {
      const { deltaBars } = action;
      const { startIndex } = state.viewport;
      const { totalBars } = state.data;
      
      let newStartIndex = startIndex + deltaBars;
      
      const maxIndex = Math.max(0, totalBars - MIN_VISIBLE_BARS);
      if (newStartIndex < 0) newStartIndex = 0;
      if (newStartIndex > maxIndex) newStartIndex = maxIndex;

      if (newStartIndex === startIndex) return state;

      return {
        ...state,
        viewport: {
          ...state.viewport,
          startIndex: newStartIndex,
        },
      };
    }

    case ActionType.ZOOM: {
      const { factor, centerX } = action; // centerX is 0.0 - 1.0 relative
      const { visibleCount, startIndex } = state.viewport;
      const { totalBars } = state.data;

      // Apply zoom factor
      let newVisibleCount = visibleCount * factor;

      // Clamp visible count
      if (newVisibleCount < MIN_VISIBLE_BARS) newVisibleCount = MIN_VISIBLE_BARS;
      if (newVisibleCount > totalBars) newVisibleCount = totalBars; 

      // Adjust start index to keep center point stable
      const centerBarIndex = startIndex + visibleCount * centerX;
      let newStartIndex = centerBarIndex - newVisibleCount * centerX;

      // Clamp start index
      if (newStartIndex < 0) newStartIndex = 0;
      const maxIndex = Math.max(0, totalBars - MIN_VISIBLE_BARS);
      if (newStartIndex > maxIndex) newStartIndex = maxIndex;

      if (newStartIndex === startIndex && newVisibleCount === visibleCount) return state;

      return {
        ...state,
        viewport: {
          ...state.viewport,
          startIndex: newStartIndex,
          visibleCount: newVisibleCount,
        },
      };
    }

    case ActionType.SET_VIEWPORT: {
      if (state.viewport.startIndex === action.startIndex &&
          state.viewport.visibleCount === action.visibleCount) return state;

      return {
        ...state,
        viewport: {
          ...state.viewport,
          startIndex: action.startIndex,
          visibleCount: action.visibleCount,
        },
      };
    }

    case ActionType.SET_RIGHT_MARGIN: {
      if (state.viewport.rightMargin === action.rightMargin) return state;

      return {
        ...state,
        viewport: {
          ...state.viewport,
          rightMargin: action.rightMargin,
        },
      };
    }

    case ActionType.RESIZE: {
      if (state.layout.width === action.width &&
          state.layout.height === action.height &&
          state.layout.dpr === action.dpr) return state;

      return {
        ...state,
        layout: {
          width: action.width,
          height: action.height,
          dpr: action.dpr,
        },
      };
    }

    case ActionType.SET_TOTAL_BARS: {
      return {
        ...state,
        data: {
          ...state.data,
          totalBars: action.count,
          version: state.data.version + 1,
        },
      };
    }

    case ActionType.HOVER: {
      const prev = state.interaction.hover;
      if (prev && prev.x === action.x && prev.y === action.y) return state;

      return {
        ...state,
        interaction: {
          ...state.interaction,
          hover: { x: action.x, y: action.y },
        },
      };
    }
    
    case ActionType.LEAVE: {
      if (state.interaction.hover === null) return state;

      return {
        ...state,
        interaction: {
          ...state.interaction,
          hover: null,
        },
      };
    }

    case ActionType.START_DRAG:
      return {
        ...state,
        interaction: {
          ...state.interaction,
          drag: { startX: action.x, startStartIndex: state.viewport.startIndex },
        },
      };
    
    case ActionType.DRAG: {
      if (!state.interaction.drag) return state;
      const { drag } = state.interaction;
      const deltaPixels = action.x - drag.startX;
      const { width } = state.layout;
      const { visibleCount } = state.viewport;
      
      const barsPerPixel = visibleCount / width;
      const deltaBars = -deltaPixels * barsPerPixel;
      
      let newStartIndex = drag.startStartIndex + deltaBars;
      
      const { totalBars } = state.data;
      if (newStartIndex < 0) newStartIndex = 0;
      const maxIndex = Math.max(0, totalBars - MIN_VISIBLE_BARS);
      if (newStartIndex > maxIndex) newStartIndex = maxIndex;

      if (newStartIndex === state.viewport.startIndex) return state;

      return {
        ...state,
        viewport: {
          ...state.viewport,
          startIndex: newStartIndex,
        },
      };
    }

    case ActionType.END_DRAG:
      return {
        ...state,
        interaction: {
          ...state.interaction,
          drag: null,
        },
      };

    case ActionType.START_PINCH:
      return {
        ...state,
        interaction: {
          ...state.interaction,
          pinch: { 
            startScale: action.scale, 
            centerX: action.centerX,
            startVisibleCount: state.viewport.visibleCount
          },
        },
      };

    case ActionType.PINCH: {
      if (!state.interaction.pinch) return state;
      const { pinch } = state.interaction;
      const { totalBars } = state.data;

      const scaleDelta = action.scale / pinch.startScale;
      // Zoom IN (fingers spread, scale > 1) -> visibleCount decreases
      let newVisibleCount = pinch.startVisibleCount / scaleDelta;
      
      if (newVisibleCount < MIN_VISIBLE_BARS) newVisibleCount = MIN_VISIBLE_BARS;
      if (newVisibleCount > totalBars) newVisibleCount = totalBars; 

      const relativeCenter = action.centerX / state.layout.width;
      const newStartIndex = (state.viewport.startIndex + state.viewport.visibleCount * relativeCenter) - newVisibleCount * relativeCenter;
      
      const maxIndex = Math.max(0, totalBars - MIN_VISIBLE_BARS);
      let clampedStartIndex = newStartIndex;
      if (clampedStartIndex < 0) clampedStartIndex = 0;
      if (clampedStartIndex > maxIndex) clampedStartIndex = maxIndex;

      return {
        ...state,
        viewport: {
            ...state.viewport,
            visibleCount: newVisibleCount,
            startIndex: clampedStartIndex
        }
      };
    }

    case ActionType.END_PINCH:
      return {
        ...state,
        interaction: {
          ...state.interaction,
          pinch: null,
        },
      };

    default:
      return assertNever(action);
  }
}
