// Minimal float32 <-> float16 conversion utilities (Array helpers)
export function f32ToF16(val: number): number {
  const f32 = new Float32Array(1);
  const u32 = new Uint32Array(f32.buffer);
  f32[0] = val;
  const x = u32[0];
  const sign = (x >> 16) & 0x8000;
  const mantissa = x & 0x007fffff;
  const exp = (x >> 23) & 0xff;
  if (exp === 0xff) {
    if (mantissa) return sign | 0x7e00; // NaN
    return sign | 0x7c00; // Inf
  }
  const halfExp = exp - 127 + 15;
  if (halfExp >= 0x1f) return sign | 0x7c00; // overflow -> inf
  if (halfExp <= 0) {
    // subnormal
    if (halfExp < -10) return sign; // underflow
    let mant = mantissa | 0x00800000;
    const shift = 14 - halfExp;
    let halfMant = mant >> shift;
    // round
    if ((mant >> (shift - 1)) & 1) halfMant += 1;
    return sign | halfMant;
  }
  let half = sign | (halfExp << 10) | (mantissa >> 13);
  // round to nearest
  if (mantissa & 0x1000) half += 1;
  return half & 0xffff;
}

export function f16ToF32(bits: number): number {
  const s = (bits & 0x8000) >> 15;
  const e = (bits & 0x7c00) >> 10;
  const f = bits & 0x03ff;
  let out: number;
  if (e === 0) {
    if (f === 0) {
      out = s ? -0 : 0;
    } else {
      // subnormal
      out = (s ? -1 : 1) * f * Math.pow(2, -24);
    }
  } else if (e === 0x1f) {
    out = f ? NaN : (s ? -Infinity : Infinity);
  } else {
    out = (s ? -1 : 1) * (1 + f / 1024) * Math.pow(2, e - 15);
  }
  return out;
}

export function f32ArrayToF16Buffer(src: Float32Array): Uint16Array {
  const out = new Uint16Array(src.length);
  for (let i = 0; i < src.length; i++) out[i] = f32ToF16(src[i]);
  return out;
}

export function f16BufferToF32Array(src: Uint16Array): Float32Array {
  const out = new Float32Array(src.length);
  for (let i = 0; i < src.length; i++) out[i] = f16ToF32(src[i]);
  return out;
}
