import type { OhlcvPoint } from '../core/types';
import { getPooledFloat32, getPooledFloat64, releasePooledFloat32, releasePooledFloat64, getPooledUint16, releasePooledUint16 } from '../util/typedArrayPool';
import { f32ArrayToF16Buffer, f16BufferToF32Array } from '../util/float16';

export interface ColumnarSlice {
  readonly time: Float64Array;
  readonly open: Float32Array;
  readonly high: Float32Array;
  readonly low: Float32Array;
  readonly close: Float32Array;
  readonly volume: Float32Array;
  readonly length: number;
  readonly globalOffset: number;
}

export class ColumnarOHLCV {
  private _capacity: number;
  private _length = 0;
  private _chunkSize = 2048; // default chunk size for per-chunk quantization

  private _time: Float64Array;
  private _open: Float32Array;
  private _high: Float32Array;
  private _low: Float32Array;
  private _close: Float32Array;
  private _volume: Float32Array;
  // optional quantized close buffer (Uint16) to save memory when enabled
  private _closeQuantized: Uint16Array | null = null;
  private _closeQuantScale: number = 1.0;
  private _closeFloat16: Uint16Array | null = null;
  // per-chunk quantization storage
  private _closeChunkQuant: Array<Uint16Array | null> = [];
  private _closeChunkScale: number[] = [];
  private _closeChunkOffset: number[] = [];

  constructor(initialCapacity = 0) {
    this._capacity = Math.max(0, initialCapacity | 0);
    this._time = getPooledFloat64(this._capacity);
    this._open = getPooledFloat32(this._capacity);
    this._high = getPooledFloat32(this._capacity);
    this._low = getPooledFloat32(this._capacity);
    this._close = getPooledFloat32(this._capacity);
    this._volume = getPooledFloat32(this._capacity);
  }

  setChunkSize(size: number) {
    this._chunkSize = Math.max(1, size | 0);
  }

  get length(): number {
    return this._length;
  }

  get capacity(): number {
    return this._capacity;
  }

  get time(): Float64Array {
    return this._time.subarray(0, this._length);
  }

  get open(): Float32Array {
    return this._open.subarray(0, this._length);
  }

  get high(): Float32Array {
    return this._high.subarray(0, this._length);
  }

  get low(): Float32Array {
    return this._low.subarray(0, this._length);
  }

  get close(): Float32Array {
    return this._close.subarray(0, this._length);
  }

  get volume(): Float32Array {
    return this._volume.subarray(0, this._length);
  }

  setData(data: readonly OhlcvPoint[]): void {
    this.ensureCapacity(data.length);
    this._length = data.length;
    for (let i = 0; i < data.length; i++) {
      const point = data[i];
      this._time[i] = point.time;
      this._open[i] = point.open;
      this._high[i] = point.high;
      this._low[i] = point.low;
      this._close[i] = point.close;
      this._volume[i] = point.volume;
    }
  }

  push(point: OhlcvPoint): void {
    this.ensureCapacity(this._length + 1);
    const i = this._length;
    this._time[i] = point.time;
    this._open[i] = point.open;
    this._high[i] = point.high;
    this._low[i] = point.low;
    this._close[i] = point.close;
    this._volume[i] = point.volume;
    this._length = i + 1;
  }

  pushRaw(
    time: number,
    open: number,
    high: number,
    low: number,
    close: number,
    volume: number
  ): void {
    this.ensureCapacity(this._length + 1);
    const i = this._length;
    this._time[i] = time;
    this._open[i] = open;
    this._high[i] = high;
    this._low[i] = low;
    this._close[i] = close;
    this._volume[i] = volume;
    this._length = i + 1;
  }

  appendOrUpdateLastRaw(
    time: number,
    open: number,
    high: number,
    low: number,
    close: number,
    volume: number
  ): boolean {
    const lastIndex = this._length - 1;
    if (lastIndex < 0 || this._time[lastIndex] !== time) {
      this.pushRaw(time, open, high, low, close, volume);
      return true;
    }

    this._open[lastIndex] = open;
    this._high[lastIndex] = high;
    this._low[lastIndex] = low;
    this._close[lastIndex] = close;
    this._volume[lastIndex] = volume;
    return false;
  }

  getLastPoint(): OhlcvPoint | null {
    if (this._length === 0) return null;
    const i = this._length - 1;
    return {
      time: this._time[i],
      open: this._open[i],
      high: this._high[i],
      low: this._low[i],
      close: this._close[i],
      volume: this._volume[i],
    };
  }

  appendOrUpdateLast(point: OhlcvPoint): boolean {
    const lastIndex = this._length - 1;
    if (lastIndex < 0 || this._time[lastIndex] !== point.time) {
      this.push(point);
      return true;
    }

    this._open[lastIndex] = point.open;
    this._high[lastIndex] = point.high;
    this._low[lastIndex] = point.low;
    this._close[lastIndex] = point.close;
    this._volume[lastIndex] = point.volume;
    return false;
  }

  getAt(index: number): OhlcvPoint | null {
    if (index < 0 || index >= this._length) return null;
    return {
      time: this._time[index],
      open: this._open[index],
      high: this._high[index],
      low: this._low[index],
      close: this._close[index],
      volume: this._volume[index],
    };
  }

  setAt(index: number, point: OhlcvPoint): boolean {
    if (index < 0 || index >= this._length) return false;
    this._time[index] = point.time;
    this._open[index] = point.open;
    this._high[index] = point.high;
    this._low[index] = point.low;
    this._close[index] = point.close;
    this._volume[index] = point.volume;
    return true;
  }

  /**
   * Overwrite the last `data.length` bars with `data`.
   * Used for partial data updates (e.g., incremental feed corrections).
   */
  spliceEnd(data: readonly OhlcvPoint[]): void {
    if (data.length === 0) return;
    const overwriteStart = Math.max(0, this._length - data.length);
    const newLength = overwriteStart + data.length;
    this.ensureCapacity(newLength);
    for (let i = 0; i < data.length; i++) {
      const dst = overwriteStart + i;
      const point = data[i];
      this._time[dst] = point.time;
      this._open[dst] = point.open;
      this._high[dst] = point.high;
      this._low[dst] = point.low;
      this._close[dst] = point.close;
      this._volume[dst] = point.volume;
    }
    this._length = newLength;
  }

  sliceView(start: number, count: number): ColumnarSlice {
    const clampedStart = Math.max(0, Math.min(this._length, start | 0));
    const safeCount = Math.max(0, count | 0);
    const end = Math.max(clampedStart, Math.min(this._length, clampedStart + safeCount));
    return {
      time: this._time.subarray(clampedStart, end),
      open: this._open.subarray(clampedStart, end),
      high: this._high.subarray(clampedStart, end),
      low: this._low.subarray(clampedStart, end),
      close: this._close.subarray(clampedStart, end),
      volume: this._volume.subarray(clampedStart, end),
      length: end - clampedStart,
      globalOffset: clampedStart,
    };
  }

  toArray(): OhlcvPoint[] {
    const out = new Array<OhlcvPoint>(this._length);
    for (let i = 0; i < this._length; i++) {
      out[i] = {
        time: this._time[i],
        open: this._open[i],
        high: this._high[i],
        low: this._low[i],
        close: this._close[i],
        volume: this._volume[i],
      };
    }
    return out;
  }

  private ensureCapacity(required: number): void {
    if (required <= this._capacity) return;
    let nextCapacity = Math.max(1, this._capacity);
    while (nextCapacity < required) {
      nextCapacity *= 2;
    }
    const nextTime = getPooledFloat64(nextCapacity);
    const nextOpen = getPooledFloat32(nextCapacity);
    const nextHigh = getPooledFloat32(nextCapacity);
    const nextLow = getPooledFloat32(nextCapacity);
    const nextClose = getPooledFloat32(nextCapacity);
    const nextVolume = getPooledFloat32(nextCapacity);

    nextTime.set(this._time.subarray(0, this._length));
    nextOpen.set(this._open.subarray(0, this._length));
    nextHigh.set(this._high.subarray(0, this._length));
    nextLow.set(this._low.subarray(0, this._length));
    nextClose.set(this._close.subarray(0, this._length));
    nextVolume.set(this._volume.subarray(0, this._length));

    // release old buffers back to pool
    releasePooledFloat64(this._time);
    releasePooledFloat32(this._open);
    releasePooledFloat32(this._high);
    releasePooledFloat32(this._low);
    releasePooledFloat32(this._close);
    releasePooledFloat32(this._volume);

    this._time = nextTime;
    this._open = nextOpen;
    this._high = nextHigh;
    this._low = nextLow;
    this._close = nextClose;
    this._volume = nextVolume;
    this._capacity = nextCapacity;
  }

  // Quantize close column into Uint16 using provided scale. Caller must choose scale such that
  // quantized values fit into [0, 65535]. This reduces memory for close column while keeping
  // a Float32 canonical copy if needed.
  quantizeCloseToUint16(scale: number, offset = 0): void {
    if (this._closeQuantized) {
      // already quantized — update scale and rewrite
      this._closeQuantScale = scale;
    } else {
      this._closeQuantized = getPooledUint16(this._capacity);
      this._closeQuantScale = scale;
    }
    const q = this._closeQuantized;
    for (let i = 0; i < this._length; i++) {
      const v = Math.round((this._close[i] - offset) * scale);
      q[i] = v < 0 ? 0 : v > 0xffff ? 0xffff : v;
    }
  }

  // Restore close from quantized buffer into float close array (in-place). Returns false if no quantized buffer.
  dequantizeCloseFromUint16(offset = 0): boolean {
    const q = this._closeQuantized;
    if (!q) return false;
    const scale = this._closeQuantScale;
    for (let i = 0; i < this._length; i++) {
      this._close[i] = q[i] / scale + offset;
    }
    return true;
  }

  freeQuantizedClose(): void {
    if (!this._closeQuantized) return;
    releasePooledUint16(this._closeQuantized);
    this._closeQuantized = null;
    this._closeQuantScale = 1.0;
  }

  // Float16 quantize (lossy) using IEEE-754 half storage.
  quantizeCloseToFloat16(): void {
    if (this._closeFloat16) return; // already present
    const arr = this._close.subarray(0, this._length);
    // produce new Uint16Array
    const f16 = f32ArrayToF16Buffer(arr);
    this._closeFloat16 = f16;
  }

  dequantizeCloseFromFloat16(): boolean {
    if (!this._closeFloat16) return false;
    const f32 = f16BufferToF32Array(this._closeFloat16);
    // write into _close in-place
    this._close.set(f32.subarray(0, this._length));
    return true;
  }

  freeFloat16Close(): void {
    this._closeFloat16 = null;
  }

  // Estimate quantization parameters (scale, offset) for the close column.
  // bits: target bit depth (default 16). margin: optional extra headroom fraction (0..1).
  estimateCloseQuantization(bits = 16, margin = 0): { scale: number; offset: number; min: number; max: number } {
    const len = this._length;
    if (len === 0) return { scale: 1, offset: 0, min: 0, max: 0 };
    let min = Infinity;
    let max = -Infinity;
    const close = this._close;
    for (let i = 0; i < len; i++) {
      const v = close[i];
      if (v < min) min = v;
      if (v > max) max = v;
    }
    const range = Math.max(0, max - min);
    const levels = (1 << bits) - 1;
    // apply margin: expand range slightly to reserve headroom
    const adjRange = range * (1 + margin);
    const scale = adjRange > 0 ? levels / adjRange : 1.0;
    const offset = min - (adjRange - range) / 2; // center expansion
    return { scale, offset, min, max };
  }

  // Convenience: auto-estimate and quantize close into Uint16.
  quantizeCloseAuto(bits = 16, margin = 0, lowP = 0.01, highP = 0.99): { scale: number; offset: number } {
    // prefer percentile-based estimator for robustness by default
    const { scale, offset } = this.estimateCloseQuantizationPercentile(bits, lowP, highP, margin);
    this.quantizeCloseToUint16(scale, offset);
    return { scale, offset };
  }

  // Per-chunk quantization: quantize each chunk independently and store per-chunk metadata.
  quantizeClosePerChunk(bits = 16, margin = 0, lowP = 0.01, highP = 0.99) {
    // free any existing chunk data
    this.freeChunkQuantization();
    const len = this._length;
    if (len === 0) return;
    const chunk = this._chunkSize;
    const chunks = Math.ceil(len / chunk);
    this._closeChunkQuant = new Array(chunks).fill(null);
    this._closeChunkScale = new Array(chunks).fill(1);
    this._closeChunkOffset = new Array(chunks).fill(0);
    for (let c = 0; c < chunks; c++) {
      const s = c * chunk;
      const e = Math.min(len, s + chunk);
      const count = e - s;
      if (count <= 0) continue;
      // build a temporary view for this chunk
      const tmp = getPooledFloat32(count);
      tmp.set(this._close.subarray(s, e));
      tmp.sort();
      const iLow = Math.floor(Math.max(0, Math.min(count - 1, Math.floor(count * lowP))));
      const iHigh = Math.floor(Math.max(0, Math.min(count - 1, Math.floor(count * highP))));
      const min = tmp[iLow];
      const max = tmp[iHigh];
      releasePooledFloat32(tmp);
      const range = Math.max(0, max - min);
      const levels = (1 << bits) - 1;
      const adjRange = range * (1 + margin);
      const scale = adjRange > 0 ? levels / adjRange : 1.0;
      const offset = min - (adjRange - range) / 2;
      const qbuf = getPooledUint16(count);
      // quantize into qbuf
      const raw = this._close;
      for (let i = 0; i < count; i++) {
        const v = Math.round((raw[s + i] - offset) * scale);
        qbuf[i] = v < 0 ? 0 : v > 0xffff ? 0xffff : v;
      }
      this._closeChunkQuant[c] = qbuf;
      this._closeChunkScale[c] = scale;
      this._closeChunkOffset[c] = offset;
    }
  }

  // Dequantize a single chunk back into the main _close array (in-place).
  dequantizeChunk(c: number): boolean {
    if (!this._closeChunkQuant || c < 0 || c >= this._closeChunkQuant.length) return false;
    const q = this._closeChunkQuant[c];
    if (!q) return false;
    const scale = this._closeChunkScale[c];
    const offset = this._closeChunkOffset[c];
    const s = c * this._chunkSize;
    const count = Math.min(this._chunkSize, this._length - s);

    // Fast-path: if wasm raw exports are available and both the quant buffer
    // and the close buffer live in the same wasm memory, call into wasm C-ABI
    // dequantize helper to perform the conversion in-place without copies.
    try {
      const raw = (globalThis as any).__MOCHART_WASM_RAW_EXPORTS__;
      if (raw && typeof raw.dequantize_into_c === 'function' && raw.memory && raw.memory.buffer) {
        // ensure both views are backed by the same ArrayBuffer
        const buf = raw.memory.buffer;
        if ((q as any).buffer === buf && (this._close as any).buffer === buf) {
          const closeByteOffset = (this._close as any).byteOffset >>> 0;
          const quantByteOffset = (q as any).byteOffset >>> 0;
          // call exported function: (close_ptr, close_len, dest_offset, quant_ptr, count, scale, offset)
          raw.dequantize_into_c(closeByteOffset, this._length, s, quantByteOffset, count, scale, offset);
          return true;
        }
      }
    } catch (e) {
      // fall through to JS fallback on any error
    }

    // Fallback: JS implementation (always correct)
    for (let i = 0; i < count; i++) {
      this._close[s + i] = q[i] / scale + offset;
    }
    return true;
  }

  // Dequantize all chunks overlapping [start, start+count)
  dequantizeRange(start: number, count: number) {
    const len = this._length;
    if (count <= 0 || start >= len) return;
    const s = Math.max(0, start | 0);
    const e = Math.min(len, s + (count | 0));
    const chunkStart = Math.floor(s / this._chunkSize);
    const chunkEnd = Math.floor((e - 1) / this._chunkSize);
    for (let c = chunkStart; c <= chunkEnd; c++) this.dequantizeChunk(c);
  }

  freeChunkQuantization() {
    if (!this._closeChunkQuant) return;
    for (let i = 0; i < this._closeChunkQuant.length; i++) {
      const q = this._closeChunkQuant[i];
      if (q) releasePooledUint16(q);
    }
    this._closeChunkQuant = [];
    this._closeChunkScale = [];
    this._closeChunkOffset = [];
  }

  // Percentile-based estimator to be robust to outliers.
  estimateCloseQuantizationPercentile(bits = 16, lowP = 0.01, highP = 0.99, margin = 0): { scale: number; offset: number; min: number; max: number } {
    const len = this._length;
    if (len === 0) return { scale: 1, offset: 0, min: 0, max: 0 };
    const tmp = getPooledFloat32(len);
    tmp.set(this._close.subarray(0, len));
    // TypedArray.sort sorts numerically for Float32Array in modern engines
    tmp.sort();
    const iLow = Math.floor(Math.max(0, Math.min(len - 1, Math.floor(len * lowP))));
    const iHigh = Math.floor(Math.max(0, Math.min(len - 1, Math.floor(len * highP))));
    const min = tmp[iLow];
    const max = tmp[iHigh];
    releasePooledFloat32(tmp);
    const range = Math.max(0, max - min);
    const levels = (1 << bits) - 1;
    const adjRange = range * (1 + margin);
    const scale = adjRange > 0 ? levels / adjRange : 1.0;
    const offset = min - (adjRange - range) / 2;
    return { scale, offset, min, max };
  }

  // Return estimated memory usage for close column (bytes) when quantized vs float.
  estimateCloseMemoryUsage(): { floatBytes: number; quantBytes: number; savingBytes: number } {
    const floatBytes = this._capacity * 4;
    const quantBytes = this._capacity * 2;
    return { floatBytes, quantBytes, savingBytes: floatBytes - quantBytes };
  }
}