import { drawHudTag, type CanvasLike2D } from './displayPrimitives';

export interface CrosshairOverlayParams {
  plotX: number;
  plotY: number;
  plotW: number;
  plotH: number;
  x: number;
  clampedY: number;
  priceAtY: number;
  strokeColor: string;
  lineWidth: number;
  labelText: string;
}

export function drawCrosshairOverlay(
  ctx: CanvasLike2D,
  params: CrosshairOverlayParams,
): void {
  const {
    plotX,
    plotY,
    plotW,
    plotH,
    x,
    clampedY,
    strokeColor,
    lineWidth,
    labelText,
  } = params;

  ctx.save();
  ctx.strokeStyle = strokeColor;
  ctx.lineWidth = lineWidth;
  ctx.beginPath();
  ctx.moveTo(x + 0.5, plotY);
  ctx.lineTo(x + 0.5, plotY + plotH);
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(plotX, clampedY + 0.5);
  ctx.lineTo(plotX + plotW, clampedY + 0.5);
  ctx.stroke();

  if (labelText.length > 0) {
    drawHudTag(ctx, {
      anchorX: plotX - 4,
      centerY: clampedY,
      text: labelText,
      backgroundColor: strokeColor,
      textColor: '#ffffff',
      font: '11px sans-serif',
      paddingX: 4,
      height: 16,
    });
  }
  ctx.restore();
}
